export const Dashboard: React.FC = () => {
  const { products, sales } = useStore();
  const [aiQuery, setAiQuery] = useState('');
  const [aiResponse, setAiResponse] = useState('');
  const [isThinking, setIsThinking] = useState(false);

  // Calculate Stats
  const totalRevenue = sales.reduce((acc, sale) => acc + sale.total, 0);
  const totalSalesCount = sales.length;
  const lowStockProducts = products.filter(p => p.stock < 5);

  // Prepare Chart Data (Last 7 sales logic simplified for demo)
  const salesData = sales.slice(0, 7).reverse().map(sale => ({
    name: new Date(sale.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
    amount: sale.total
  }));

  const handleAskAI = async () => {
    if (!aiQuery.trim()) return;
    setIsThinking(true);
    setAiResponse('');

    const response = await getBusinessInsights(products, sales, aiQuery);

    setAiResponse(response);
    setIsThinking(false);
  };

  return (
    <div className="space-y-6 animate-fade-in">
      <header className="mb-8">
        <h2 className="text-2xl font-bold text-slate-800">Visão Geral</h2>
        <p className="text-slate-500">Acompanhe o desempenho do seu negócio.</p>
