import React, { useState } from 'react';
import { useStore } from '../context/StoreContext';
import { Product } from '../types';
import { CATEGORIES } from '../constants';
import { Plus, Search, Edit2, Trash2, X, Sparkles, Box } from 'lucide-react';
import { generateProductDescription } from '../services/geminiService';

export const Inventory: React.FC = () => {
  const { products, deleteProduct, addProduct, updateProduct } = useStore();
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Form State
  const [formData, setFormData] = useState<Partial<Product>>({
    name: '', category: CATEGORIES[0], price: 0, stock: 0, description: '', imageUrl: 'https://picsum.photos/200/200'
  });
  const [isGenerating, setIsGenerating] = useState(false);
  const [isEditing, setIsEditing] = useState(false);

  const handleOpenModal = (product?: Product) => {
    if (product) {
      setFormData(product);
      setIsEditing(true);
    } else {
      setFormData({
        name: '', category: CATEGORIES[0], price: 0, stock: 0, description: '', imageUrl: `https://picsum.photos/200/200?random=${Date.now()}`
      });
      setIsEditing(false);
    }
    setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.price) return;

    const productToSave = {
      ...formData,
      id: isEditing ? formData.id! : Date.now().toString(),
      price: Number(formData.price),
      stock: Number(formData.stock),
    } as Product;

    if (isEditing) {
      updateProduct(productToSave);
    } else {
      addProduct(productToSave);
    }
    setIsModalOpen(false);
  };

  const handleGenerateDescription = async () => {
    if (!formData.name || !formData.category) return;
    setIsGenerating(true);
    const desc = await generateProductDescription(formData.name, formData.category);
    setFormData(prev => ({ ...prev, description: desc }));
    setIsGenerating(false);
  };

  const filteredProducts = products.filter(p => 
