  const handleExportBackup = () => {
    const data = {
      timestamp: Date.now(),
      version: 1,
      products,
      sales
    };

    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `smartpos-backup-${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const triggerImport = () => {
    // Password protection logic
    const password = window.prompt("Digite a senha de administrador para restaurar o backup:");
    if (password === "admin") {
      fileInputRef.current?.click();
    } else if (password !== null) {
      alert("Senha incorreta.");
    }
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const content = event.target?.result as string;
        const parsed = JSON.parse(content);

        if (!parsed.products || !parsed.sales) {
          throw new Error("Formato de arquivo inválido");
        }

        if (window.confirm(`Backup encontrado de ${new Date(parsed.timestamp).toLocaleString()}. Deseja restaurar? Isso substituirá os dados atuais.`)) {
          importData(parsed);
          alert("Backup restaurado com sucesso!");
        }
      } catch (err) {
        alert("Erro ao ler o arquivo de backup. Verifique se é um arquivo JSON válido.");
        console.error(err);
