import { useStore } from '../context/StoreContext';
import { Download, Upload, Trash2, AlertTriangle, Save, RefreshCw, X, Lock, Shield, Key } from 'lucide-react';

export const Settings: React.FC = () => {
  const { products, sales, importData, resetSystem, updateAdminPassword, isDefaultPassword } = useStore();
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Modal State
  // 'reset-initial' is a special state for first time reset where user must create a password
  const [modalType, setModalType] = useState<'restore' | 'reset' | 'reset-initial' | null>(null);
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState(''); // Only used for reset-initial
  const [pendingFileContent, setPendingFileContent] = useState<any>(null);
  const [error, setError] = useState('');

  // Password Change State
  const [pwdForm, setPwdForm] = useState({ current: '', new: '', confirm: '' });
  const [pwdMessage, setPwdMessage] = useState<{type: 'success' | 'error', text: string} | null>(null);

  const handleExportBackup = () => {
    const data = {
      timestamp: Date.now(),
      version: 1,
      products,
      sales
    };

    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `smartpos-backup-${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const content = event.target?.result as string;
        const parsed = JSON.parse(content);

        if (!parsed.products || !parsed.sales) {
          throw new Error("Formato de arquivo inválido");
        }

        setPendingFileContent(parsed);
        setModalType('restore');
        // Clear input
        if (fileInputRef.current) fileInputRef.current.value = '';
      } catch (err) {
        alert("Erro ao ler o arquivo de backup. Verifique se é um arquivo JSON válido.");
        console.error(err);
      }
    };
    reader.readAsText(file);
  };

  const handleSubmitPassword = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');

    if (modalType === 'restore') {
      const success = importData(pendingFileContent, password);
      if (success) {
        closeModal();
        alert('Backup restaurado com sucesso!');
      } else {
        setError('Senha incorreta.');
      }
    } else if (modalType === 'reset') {
      const success = resetSystem(password);
      if (success) {
        closeModal();
        alert('Sistema resetado com sucesso!');
      } else {
        setError('Senha incorreta.');
      }
    } else if (modalType === 'reset-initial') {
      if (password.length < 4) {
        setError('A senha deve ter pelo menos 4 caracteres.');
        return;
      }
      if (password !== confirmPassword) {
        setError('As senhas não conferem.');
        return;
      }

      // Update password first (from 'admin' to new password)
      const pwUpdateSuccess = updateAdminPassword('admin', password);

      if (pwUpdateSuccess) {
        // Then perform the reset with the NEW password
        const resetSuccess = resetSystem(password);
        if (resetSuccess) {
          closeModal();
          alert('Senha definida e sistema resetado com sucesso!');
        } else {
          setError('Erro ao resetar sistema.');
        }
      } else {
        setError('Erro ao atualizar senha.');
      }
    }
  };

  const handleChangePassword = (e: React.FormEvent) => {
    e.preventDefault();
    setPwdMessage(null);

    if (pwdForm.new.length < 4) {
      setPwdMessage({ type: 'error', text: 'A nova senha deve ter pelo menos 4 caracteres.' });
      return;
    }

    if (pwdForm.new !== pwdForm.confirm) {
      setPwdMessage({ type: 'error', text: 'A confirmação de senha não confere.' });
      return;
    }

    const success = updateAdminPassword(pwdForm.current, pwdForm.new);
    if (success) {
      setPwdMessage({ type: 'success', text: 'Senha alterada com sucesso!' });
      setPwdForm({ current: '', new: '', confirm: '' });
    } else {
      setPwdMessage({ type: 'error', text: 'Senha atual incorreta.' });
    }
  };

  const closeModal = () => {
    setModalType(null);
    setPassword('');
    setConfirmPassword('');
    setError('');
    setPendingFileContent(null);
  };

  // Determine Modal Content based on type
  const isDanger = modalType === 'reset' || modalType === 'reset-initial';
  const modalTitle = modalType === 'restore' ? 'Restaurar Backup' : 
                     modalType === 'reset-initial' ? 'Configurar Senha & Resetar' : 'Resetar Sistema';
  const modalIcon = isDanger ? <AlertTriangle size={18} /> : <Lock size={18} />;

  return (
    <div className="space-y-8 animate-fade-in max-w-4xl pb-12">
      <header>
        <h2 className="text-2xl font-bold text-slate-800">Configurações</h2>
        <p className="text-slate-500">Gerencie seus dados, backups e segurança.</p>
      </header>

      <div className="grid gap-6">

        {/* Security Section */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
           <div className="flex items-start gap-4 mb-6">
            <div className="p-3 bg-indigo-100 text-indigo-600 rounded-full">
              <Shield size={24} />
            </div>
            <div>
              <h3 className="text-lg font-bold text-slate-800">Segurança</h3>
              <p className="text-sm text-slate-500">Altere a senha de administrador utilizada para ações críticas.</p>
            </div>
          </div>

          <form onSubmit={handleChangePassword} className="max-w-md bg-slate-50 p-6 rounded-xl border border-slate-200 space-y-4">
             {pwdMessage && (
              <div className={`p-3 rounded-lg text-sm font-medium ${pwdMessage.type === 'success' ? 'bg-green-100 text-green-700' : 'bg-red-100 text-red-700'}`}>
                {pwdMessage.text}
              </div>
            )}

            <div className="space-y-2">
              <label className="text-xs font-bold text-slate-500 uppercase flex items-center gap-1">
                <Key size={12} /> Senha Atual
              </label>
              <input 
                type="password" 
                value={pwdForm.current}
                onChange={e => setPwdForm({...pwdForm, current: e.target.value})}
                className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:outline-none bg-white"
                required
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div className="space-y-2">
                <label className="text-xs font-bold text-slate-500 uppercase">Nova Senha</label>
                <input 
                  type="password" 
                  value={pwdForm.new}
                  onChange={e => setPwdForm({...pwdForm, new: e.target.value})}
                  className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:outline-none bg-white"
                  required
                />
              </div>
              <div className="space-y-2">
                <label className="text-xs font-bold text-slate-500 uppercase">Confirmar</label>
                <input 
                  type="password" 
                  value={pwdForm.confirm}
                  onChange={e => setPwdForm({...pwdForm, confirm: e.target.value})}
                  className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:outline-none bg-white"
                  required
                />
              </div>
            </div>

            <div className="pt-2">
              <button 
                type="submit" 
                className="w-full px-4 py-2 bg-indigo-600 text-white rounded-lg font-medium hover:bg-indigo-700 transition-colors shadow-sm"
              >
                Atualizar Senha
              </button>
            </div>
          </form>
        </div>

        {/* Backup Section */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <div className="flex items-start gap-4 mb-6">
            <div className="p-3 bg-blue-100 text-blue-600 rounded-full">
              <Save size={24} />
            </div>
            <div>
              <h3 className="text-lg font-bold text-slate-800">Backup e Restauração</h3>
              <p className="text-sm text-slate-500">Salve seus dados localmente ou restaure de um arquivo anterior.</p>
            </div>
          </div>

          <div className="flex flex-col sm:flex-row gap-4">
            <button 
              onClick={handleExportBackup}
              className="flex-1 flex items-center justify-center gap-2 bg-slate-800 text-white px-6 py-4 rounded-xl hover:bg-slate-700 transition-colors"
            >
              <Download size={20} />
              <div className="text-left">
                <span className="block font-bold">Fazer Backup</span>
                <span className="text-xs text-slate-400">Baixar arquivo .json</span>
              </div>
            </button>

            <button 
              onClick={() => fileInputRef.current?.click()}
              className="flex-1 flex items-center justify-center gap-2 bg-white border-2 border-slate-200 text-slate-700 px-6 py-4 rounded-xl hover:border-primary hover:text-primary transition-colors"
            >
              <Upload size={20} />
              <div className="text-left">
                <span className="block font-bold">Restaurar Backup</span>
                <span className="text-xs text-slate-400">Requer senha de admin</span>
              </div>
            </button>
            <input 
              type="file" 
              ref={fileInputRef} 
              onChange={handleFileChange} 
              accept=".json" 
              className="hidden" 
            />
          </div>
        </div>

        {/* Danger Zone */}
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-red-100 relative overflow-hidden">
          <div className="absolute top-0 right-0 p-4 opacity-5">
            <AlertTriangle size={120} className="text-red-500" />
          </div>

          <div className="flex items-start gap-4 mb-6 relative z-10">
            <div className="p-3 bg-red-100 text-red-600 rounded-full">
              <Trash2 size={24} />
            </div>
            <div>
              <h3 className="text-lg font-bold text-slate-800">Zona de Perigo</h3>
              <p className="text-sm text-slate-500">Ações destrutivas que não podem ser desfeitas.</p>
            </div>
          </div>

          <div className="space-y-4 relative z-10">
            <div className="flex items-center justify-between p-4 bg-red-50 rounded-xl border border-red-100">
              <div>
                <h4 className="font-bold text-red-900">Reset de Fábrica</h4>
                <p className="text-xs text-red-700">Apaga todos os produtos, vendas e restaura os dados de exemplo.</p>
              </div>
              <button 
                onClick={() => setModalType(isDefaultPassword ? 'reset-initial' : 'reset')}
                className="px-4 py-2 bg-red-600 text-white rounded-lg text-sm font-medium hover:bg-red-700 transition-colors flex items-center gap-2"
              >
                <RefreshCw size={14} />
                Reset Total
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Security Modal */}
      {modalType && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/40 backdrop-blur-sm animate-fade-in">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-sm overflow-hidden">
            <div className={`p-4 border-b border-slate-100 flex justify-between items-center ${isDanger ? 'bg-red-50' : 'bg-blue-50'}`}>
              <h3 className={`font-bold flex items-center gap-2 ${isDanger ? 'text-red-700' : 'text-blue-700'}`}>
                {modalIcon}
                {modalTitle}
              </h3>
              <button onClick={closeModal} className="text-slate-400 hover:text-slate-600">
                <X size={20} />
              </button>
            </div>

            <form onSubmit={handleSubmitPassword} className="p-6 space-y-4">
              <p className="text-sm text-slate-600">
                {modalType === 'reset' && "Você está prestes a apagar todos os dados e restaurar o estado inicial. Digite a senha de administrador para confirmar."}
                {modalType === 'restore' && "A restauração irá substituir todos os produtos e vendas atuais pelos dados do backup. Digite a senha de administrador para continuar."}
                {modalType === 'reset-initial' && "Para realizar o Reset de Fábrica pela primeira vez, você precisa definir uma senha de administrador segura."}
              </p>

              {modalType === 'reset-initial' ? (
                // Initial Reset: Create Password Fields
                <>
                  <div className="space-y-2">
                    <label className="text-xs font-bold text-slate-500 uppercase">Crie sua Senha Admin</label>
                    <input 
                      autoFocus
                      type="password" 
                      value={password}
                      onChange={e => setPassword(e.target.value)}
                      className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-red-500 focus:border-red-500 focus:outline-none"
                      placeholder="Nova senha..."
                      required
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-xs font-bold text-slate-500 uppercase">Confirmar Senha</label>
                    <input 
                      type="password" 
                      value={confirmPassword}
                      onChange={e => setConfirmPassword(e.target.value)}
                      className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-red-500 focus:border-red-500 focus:outline-none"
                      placeholder="Repita a senha..."
                      required
                    />
                  </div>
                </>
              ) : (
                // Standard: Verify Password Field
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-500 uppercase">Senha de Administrador</label>
                  <input 
                    autoFocus
                    type="password" 
                    value={password}
                    onChange={e => setPassword(e.target.value)}
                    className={`w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:outline-none ${isDanger ? 'focus:ring-red-500 focus:border-red-500' : 'focus:ring-blue-500 focus:border-blue-500'}`}
                    placeholder="Digite a senha..."
                  />
                </div>
              )}

              {error && <p className="text-xs text-red-500 font-medium">{error}</p>}

              <div className="flex gap-3 pt-2">
                <button 
                  type="button" 
                  onClick={closeModal}
                  className="flex-1 px-4 py-2 border border-slate-200 text-slate-600 rounded-lg hover:bg-slate-50 font-medium text-sm"
                >
                  Cancelar
                </button>
                <button 
                  type="submit" 
                  className={`flex-1 px-4 py-2 text-white rounded-lg font-medium text-sm shadow-md ${isDanger ? 'bg-red-600 hover:bg-red-700 shadow-red-200' : 'bg-blue-600 hover:bg-blue-700 shadow-blue-200'}`}
                >
                  {modalType === 'reset-initial' ? 'Salvar & Resetar' : 'Confirmar'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

