import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { Product, Sale, CartItem } from '../types';
import { INITIAL_PRODUCTS } from '../constants';

interface StoreContextType {
  products: Product[];
  sales: Sale[];
  cart: CartItem[];
  isDefaultPassword: boolean;
  addProduct: (product: Product) => void;
  updateProduct: (product: Product) => void;
  deleteProduct: (id: string) => void;
  addToCart: (product: Product) => void;
  removeFromCart: (productId: string) => void;
  updateCartQuantity: (productId: string, delta: number) => void;
  clearCart: () => void;
  completeSale: (paymentMethod: Sale['paymentMethod']) => void;
  cancelSale: (saleId: string, password: string) => { success: boolean; message: string };
  clearSalesHistory: (password: string) => boolean;
  importData: (data: any, password: string) => boolean;
  resetSystem: (password: string) => boolean;
  updateAdminPassword: (currentPw: string, newPw: string) => boolean;
}

const StoreContext = createContext<StoreContextType | undefined>(undefined);

export const StoreProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('smartpos_products');
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });

  const [sales, setSales] = useState<Sale[]>(() => {
    const saved = localStorage.getItem('smartpos_sales');
    return saved ? JSON.parse(saved) : [];
  });

  const [cart, setCart] = useState<CartItem[]>([]);

  const [adminPassword, setAdminPassword] = useState<string>(() => {
    return localStorage.getItem('smartpos_password') || 'admin';
  });

  const isDefaultPassword = adminPassword === 'admin';

  useEffect(() => {
    localStorage.setItem('smartpos_products', JSON.stringify(products));
  }, [products]);

  useEffect(() => {
    localStorage.setItem('smartpos_sales', JSON.stringify(sales));
  }, [sales]);

  useEffect(() => {
    localStorage.setItem('smartpos_password', adminPassword);
  }, [adminPassword]);

  const addProduct = (product: Product) => setProducts(prev => [...prev, product]);

  const updateProduct = (updatedProduct: Product) => {
    setProducts(prev => prev.map(p => p.id === updatedProduct.id ? updatedProduct : p));
  };

  const deleteProduct = (id: string) => setProducts(prev => prev.filter(p => p.id !== id));

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => 
          item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item
        );
      }
      return [...prev, { ...product, quantity: 1 }];
    });
  };

  const removeFromCart = (productId: string) => {
    setCart(prev => prev.filter(item => item.id !== productId));
  };

  const updateCartQuantity = (productId: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === productId) {
        const newQty = item.quantity + delta;
        return newQty > 0 ? { ...item, quantity: newQty } : item;
      }
      return item;
    }));
  };

  const clearCart = () => setCart([]);

  const completeSale = (paymentMethod: Sale['paymentMethod']) => {
    const total = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

    let nextIdNum = 1;
    if (sales.length > 0) {
      const lastIdStr = sales[0].id;
      const lastIdNum = parseInt(lastIdStr);
      if (!isNaN(lastIdNum) && lastIdNum < 1000000000000) {
        nextIdNum = lastIdNum + 1;
      } else {
        nextIdNum = sales.length + 1;
      }
    }

    const newSale: Sale = {
      id: nextIdNum.toString(),
      timestamp: Date.now(),
      total,
      items: [...cart],
      paymentMethod,
      status: 'completed'
    };

    setSales(prev => [newSale, ...prev]);

    setProducts(prev => prev.map(p => {
      const cartItem = cart.find(c => c.id === p.id);
      if (cartItem) {
        return { ...p, stock: Math.max(0, p.stock - cartItem.quantity) };
      }
      return p;
    }));

    clearCart();
  };

  const cancelSale = (saleId: string, password: string) => {
    if (password !== adminPassword) {
      return { success: false, message: 'Senha incorreta.' };
    }

    const saleIndex = sales.findIndex(s => s.id === saleId);
    if (saleIndex === -1) return { success: false, message: 'Venda não encontrada.' };
    if (sales[saleIndex].status === 'canceled') return { success: false, message: 'Venda já foi cancelada.' };

    const saleToCancel = sales[saleIndex];

    // Mark as canceled
    const updatedSales = [...sales];
    updatedSales[saleIndex] = { ...saleToCancel, status: 'canceled' };
    setSales(updatedSales);

    // Repose stock
    setProducts(prev => prev.map(p => {
      const itemToReturn = saleToCancel.items.find(item => item.id === p.id);
      if (itemToReturn) {
        return { ...p, stock: p.stock + itemToReturn.quantity };
      }
      return p;
    }));

    return { success: true, message: 'Venda estornada com sucesso. Estoque reposto.' };
  };

  const validatePassword = (password: string): boolean => password === adminPassword;

  const updateAdminPassword = (currentPw: string, newPw: string): boolean => {
    if (validatePassword(currentPw)) {
      setAdminPassword(newPw);
      return true;
    }
    return false;
  };

  const clearSalesHistory = (password: string): boolean => {
    if (validatePassword(password)) {
      setSales([]);
      return true;
    }
    return false;
  };

  const importData = (data: any, password: string): boolean => {
    if (!validatePassword(password)) return false;
    if (data.products) setProducts(data.products);
    if (data.sales) setSales(data.sales);
    return true;
  };

  const resetSystem = (password: string): boolean => {
    if (!validatePassword(password)) return false;
    setProducts(INITIAL_PRODUCTS);
    setSales([]);
    setCart([]);
    return true;
  };

  return (
    <StoreContext.Provider value={{
      products,
      sales,
      cart,
      isDefaultPassword,
      addProduct,
      updateProduct,
      deleteProduct,
      addToCart,
      removeFromCart,
      updateCartQuantity,
      clearCart,
      completeSale,
      cancelSale,
      clearSalesHistory,
      importData,
      resetSystem,
      updateAdminPassword
    }}>
      {children}
    </StoreContext.Provider>
  );
};

