import React, { useMemo } from 'react';
import { useStore } from '../context/StoreContext';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { DollarSign, ShoppingBag, AlertTriangle, TrendingUp, Trophy } from 'lucide-react';

export const Dashboard: React.FC = () => {
  const { products, sales } = useStore();

  // Filter out canceled sales for stats
  const activeSales = useMemo(() => sales.filter(s => s.status !== 'canceled'), [sales]);

  // Calculate Stats
  const totalRevenue = activeSales.reduce((acc, sale) => acc + sale.total, 0);
  const totalSalesCount = activeSales.length;
  const lowStockProducts = products.filter(p => p.stock < 5);

  // Prepare Chart Data (Last 7 active sales)
  const salesData = activeSales.slice(0, 7).reverse().map(sale => ({
    name: new Date(sale.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
    amount: sale.total
  }));

  // Calculate Top Selling Products (Ignora vendas canceladas)
  const topProducts = useMemo(() => {
    const productCounts: Record<string, number> = {};

    activeSales.forEach(sale => {
      sale.items.forEach(item => {
        productCounts[item.id] = (productCounts[item.id] || 0) + item.quantity;
      });
    });

    return Object.entries(productCounts)
      .sort(([, a], [, b]) => b - a)
      .slice(0, 5)
      .map(([id, count]) => {
        const product = products.find(p => p.id === id);
        return product ? { ...product, soldCount: count } : null;
      })
      .filter((item): item is (typeof products[0] & { soldCount: number }) => item !== null);
  }, [activeSales, products]);

  return (
    <div className="space-y-6 animate-fade-in">
      <header className="mb-8">
        <h2 className="text-2xl font-bold text-slate-800">Visão Geral</h2>
        <p className="text-slate-500">Acompanhe o desempenho do seu negócio em tempo real.</p>
      </header>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-4">
          <div className="p-3 bg-emerald-100 text-emerald-600 rounded-full">
            <DollarSign size={24} />
          </div>
          <div>
            <p className="text-sm text-slate-500 font-medium">Faturamento Total</p>
            <p className="text-2xl font-bold text-slate-800">R$ {totalRevenue.toFixed(2)}</p>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-4">
          <div className="p-3 bg-blue-100 text-blue-600 rounded-full">
            <ShoppingBag size={24} />
          </div>
          <div>
            <p className="text-sm text-slate-500 font-medium">Vendas Realizadas</p>
            <p className="text-2xl font-bold text-slate-800">{totalSalesCount}</p>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-4">
          <div className="p-3 bg-amber-100 text-amber-600 rounded-full">
            <AlertTriangle size={24} />
          </div>
          <div>
            <p className="text-sm text-slate-500 font-medium">Estoque Baixo</p>
            <p className="text-2xl font-bold text-slate-800">{lowStockProducts.length}</p>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-4">
          <div className="p-3 bg-purple-100 text-purple-600 rounded-full">
            <TrendingUp size={24} />
          </div>
          <div>
            <p className="text-sm text-slate-500 font-medium">Ticket Médio</p>
            <p className="text-2xl font-bold text-slate-800">
              R$ {(totalSalesCount > 0 ? totalRevenue / totalSalesCount : 0).toFixed(2)}
            </p>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold text-slate-800 mb-6">Últimas Vendas</h3>
          <div className="h-64 w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={salesData}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} dy={10} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} prefix="R$ " />
                <Tooltip 
                  cursor={{fill: '#f1f5f9'}}
                  contentStyle={{borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)'}} 
                />
                <Bar dataKey="amount" fill="#10b981" radius={[4, 4, 0, 0]} barSize={40} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col">
          <div className="flex items-center gap-2 mb-6">
            <div className="p-2 bg-yellow-100 text-yellow-600 rounded-lg">
              <Trophy size={20} />
            </div>
            <h3 className="text-lg font-bold text-slate-800">Mais Vendidos</h3>
          </div>

          <div className="flex-1 overflow-y-auto space-y-4 pr-2">
            {topProducts.length === 0 ? (
              <p className="text-slate-400 text-sm text-center mt-8">Nenhuma venda válida registrada.</p>
            ) : (
              topProducts.map((product, index) => (
                <div key={product.id} className="flex items-center gap-3 p-2 hover:bg-slate-50 rounded-xl transition-colors">
                  <span className={`w-6 h-6 flex items-center justify-center text-xs font-bold rounded-full ${
                    index === 0 ? 'bg-yellow-100 text-yellow-700' : 
                    index === 1 ? 'bg-slate-100 text-slate-700' : 
                    index === 2 ? 'bg-amber-100 text-amber-700' : 'bg-slate-50 text-slate-500'
                  }`}>
                    {index + 1}
                  </span>
                  <img src={product.imageUrl} alt="" className="w-10 h-10 rounded-lg object-cover bg-slate-100" />
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium text-slate-800 truncate">{product.name}</p>
                    <p className="text-xs text-slate-500">{product.soldCount} unidades vendidas</p>
                  </div>
                  <div className="text-right">
                     <p className="text-xs font-bold text-emerald-600">R$ {product.price.toFixed(2)}</p>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { useStore } from '../context/StoreContext';
import { Clock, CreditCard, Banknote, QrCode, Trash2, AlertTriangle, X, RotateCcw, Ban, ShieldCheck, Key } from 'lucide-react';

export const SalesHistory: React.FC = () => {
  const { sales, clearSalesHistory, cancelSale, isDefaultPassword, updateAdminPassword } = useStore();

  // Modals
  const [showClearModal, setShowClearModal] = useState(false);
  const [saleToCancel, setSaleToCancel] = useState<string | null>(null);

  // Password state for both modes
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [error, setError] = useState('');

  const getPaymentIcon = (method: string) => {
    switch (method) {
      case 'credit': return <CreditCard size={16} className="text-blue-500" />;
      case 'debit': return <CreditCard size={16} className="text-sky-500" />;
      case 'cash': return <Banknote size={16} className="text-green-500" />;
      case 'pix': return <QrCode size={16} className="text-teal-500" />;
      default: return <CreditCard size={16} />;
    }
  };

  const getPaymentLabel = (method: string) => {
    const labels: Record<string, string> = { credit: 'Cartão de Crédito', debit: 'Débito', cash: 'Dinheiro', pix: 'Pix' };
    return labels[method] || method;
  };

  const handleClearHistory = (e: React.FormEvent) => {
    e.preventDefault();
    const success = clearSalesHistory(password);
    if (success) {
      closeModals();
    } else {
      setError('Senha incorreta.');
    }
  };

  const handleCancelSale = (e: React.FormEvent) => {
    e.preventDefault();
    if (!saleToCancel) return;
    setError('');

    // Flow 1: First Use (Create Password)
    if (isDefaultPassword) {
      if (password.length < 4) {
        setError('A senha deve ter pelo menos 4 caracteres.');
        return;
      }
      if (password !== confirmPassword) {
        setError('As senhas não conferem.');
        return;
      }

      // Update password first
      const pwSuccess = updateAdminPassword('admin', password);
      if (!pwSuccess) {
        setError('Erro ao configurar senha.');
        return;
      }

      // Then cancel sale with the NEW password
      const result = cancelSale(saleToCancel, password);
      if (result.success) {
        alert('Senha configurada e venda estornada com sucesso!');
        closeModals();
      } else {
        setError(result.message);
      }
    } 
    // Flow 2: Standard Refund (Confirm with current password)
    else {
      const result = cancelSale(saleToCancel, password);
      if (result.success) {
        closeModals();
        alert(result.message);
      } else {
        setError(result.message);
      }
    }
  };

  const closeModals = () => {
    setShowClearModal(false);
    setSaleToCancel(null);
    setPassword('');
    setConfirmPassword('');
    setError('');
  };

  return (
    <div className="space-y-6">
      <header className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Histórico de Vendas</h2>
          <p className="text-slate-500">Registro completo de todas as transações.</p>
        </div>
        {sales.length > 0 && (
          <button 
            onClick={() => setShowClearModal(true)}
            className="flex items-center gap-2 px-4 py-2 text-red-600 bg-red-50 hover:bg-red-100 rounded-lg transition-colors text-sm font-medium"
          >
            <Trash2 size={16} />
            <span>Limpar Histórico</span>
          </button>
        )}
      </header>

      <div className="space-y-4">
        {sales.map(sale => {
          const isCanceled = sale.status === 'canceled';

          return (
            <div 
              key={sale.id} 
              className={`bg-white border ${isCanceled ? 'border-red-100 opacity-75' : 'border-slate-100'} rounded-xl p-4 shadow-sm hover:shadow-md transition-shadow flex flex-col md:flex-row gap-4 items-start md:items-center relative overflow-hidden`}
            >
              {isCanceled && (
                <div className="absolute top-0 right-0 p-2">
                  <span className="flex items-center gap-1 text-[10px] font-bold uppercase bg-red-100 text-red-600 px-2 py-0.5 rounded-full">
                    <Ban size={10} /> Estornado
                  </span>
                </div>
              )}

              <div className="flex items-center gap-3 w-full md:w-auto">
                <div className={`w-10 h-10 rounded-full flex items-center justify-center ${isCanceled ? 'bg-red-50 text-red-400' : 'bg-slate-100 text-slate-500'}`}>
                  <Clock size={20} />
                </div>
                <div>
                  <p className={`font-bold ${isCanceled ? 'text-slate-400 line-through' : 'text-slate-800'}`}>Pedido #{sale.id.padStart(4, '0')}</p>
                  <p className="text-xs text-slate-500">{new Date(sale.timestamp).toLocaleString('pt-BR')}</p>
                </div>
              </div>

              <div className="flex-1 w-full md:w-auto space-y-1">
                <div className="flex flex-wrap gap-2">
                  {sale.items.map((item, idx) => (
                    <span key={idx} className={`inline-flex items-center px-2 py-1 border rounded text-xs ${isCanceled ? 'bg-slate-50 border-slate-200 text-slate-400' : 'bg-slate-50 border-slate-200 text-slate-600'}`}>
                      {item.quantity}x {item.name}
                    </span>
                  ))}
                </div>
              </div>

              <div className="flex items-center gap-6 w-full md:w-auto justify-between md:justify-end">
                <div className="flex items-center gap-2 text-sm text-slate-600 bg-slate-50 px-3 py-1 rounded-lg">
                  {getPaymentIcon(sale.paymentMethod)}
                  <span>{getPaymentLabel(sale.paymentMethod)}</span>
                </div>

                <div className="text-right min-w-[100px]">
                  <p className="text-xs text-slate-400 font-medium uppercase">Total</p>
                  <p className={`text-lg font-bold ${isCanceled ? 'text-slate-400 line-through' : 'text-emerald-600'}`}>R$ {sale.total.toFixed(2)}</p>
                </div>

                {!isCanceled && (
                  <button 
                    onClick={() => setSaleToCancel(sale.id)}
                    className="p-2 text-amber-600 hover:bg-amber-50 rounded-lg transition-colors group relative"
                    title="Estornar Venda"
                  >
                    <RotateCcw size={18} />
                  </button>
                )}
              </div>
            </div>
          );
        })}

        {sales.length === 0 && (
          <div className="text-center py-12 bg-white rounded-2xl border border-dashed border-slate-200">
            <p className="text-slate-400">Nenhuma venda registrada ainda.</p>
          </div>
        )}
      </div>

      {/* Clear History Modal */}
      {showClearModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/40 backdrop-blur-sm animate-fade-in">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-sm overflow-hidden">
            <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-red-50">
              <h3 className="font-bold text-red-700 flex items-center gap-2">
                <AlertTriangle size={18} />
                Limpar Histórico
              </h3>
              <button onClick={closeModals} className="text-red-400 hover:text-red-600">
                <X size={20} />
              </button>
            </div>

            <form onSubmit={handleClearHistory} className="p-6 space-y-4">
              <p className="text-sm text-slate-600">
                Esta ação apagará permanentemente todo o histórico de vendas. Digite a senha de administrador para confirmar.
              </p>

              <div className="space-y-2">
                <label className="text-xs font-bold text-slate-500 uppercase">Senha Admin</label>
                <input 
                  autoFocus
                  type="password" 
                  value={password}
                  onChange={e => setPassword(e.target.value)}
                  className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-red-500 focus:border-red-500 focus:outline-none"
                  placeholder="Digite a senha..."
                />
                {error && <p className="text-xs text-red-500 font-medium">{error}</p>}
              </div>

              <div className="flex gap-3 pt-2">
                <button type="button" onClick={closeModals} className="flex-1 px-4 py-2 border border-slate-200 text-slate-600 rounded-lg hover:bg-slate-50 font-medium text-sm">
                  Cancelar
                </button>
                <button type="submit" className="flex-1 px-4 py-2 bg-red-600 text-white rounded-lg hover:bg-red-700 font-medium text-sm shadow-md">
                  Limpar Tudo
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Cancel Sale Modal / First Use Password Creation */}
      {saleToCancel && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/40 backdrop-blur-sm animate-fade-in">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-sm overflow-hidden">
            <div className={`p-4 border-b border-slate-100 flex justify-between items-center ${isDefaultPassword ? 'bg-indigo-50' : 'bg-amber-50'}`}>
              <h3 className={`font-bold flex items-center gap-2 ${isDefaultPassword ? 'text-indigo-700' : 'text-amber-700'}`}>
                {isDefaultPassword ? <ShieldCheck size={18} /> : <RotateCcw size={18} />}
                {isDefaultPassword ? 'Primeiro Uso: Criar Senha' : 'Confirmar Estorno'}
              </h3>
              <button onClick={closeModals} className="text-slate-400 hover:text-slate-600">
                <X size={20} />
              </button>
            </div>

            <form onSubmit={handleCancelSale} className="p-6 space-y-4">
              <p className="text-sm text-slate-600">
                {isDefaultPassword 
                  ? "Para realizar estornos, você deve primeiro criar sua senha de administrador definitiva." 
                  : <>Você está estornando o pedido <strong>#{saleToCancel.padStart(4, '0')}</strong>. Digite sua senha para confirmar.</>
                }
              </p>

              {isDefaultPassword ? (
                <>
                  <div className="space-y-2">
                    <label className="text-xs font-bold text-slate-500 uppercase flex items-center gap-1">
                      <Key size={12} /> Nova Senha Admin
                    </label>
                    <input 
                      autoFocus
                      type="password" 
                      value={password}
                      onChange={e => setPassword(e.target.value)}
                      className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 focus:outline-none"
                      placeholder="Mínimo 4 caracteres..."
                      required
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-xs font-bold text-slate-500 uppercase">Confirmar Senha</label>
                    <input 
                      type="password" 
                      value={confirmPassword}
                      onChange={e => setConfirmPassword(e.target.value)}
                      className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:border-indigo-500 focus:outline-none"
                      placeholder="Repita a nova senha..."
                      required
                    />
                  </div>
                </>
              ) : (
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-500 uppercase">Senha Admin</label>
                  <input 
                    autoFocus
                    type="password" 
                    value={password}
                    onChange={e => setPassword(e.target.value)}
                    className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-amber-500 focus:border-amber-500 focus:outline-none"
                    placeholder="Digite sua senha..."
                  />
                </div>
              )}

              {error && <p className="text-xs text-red-500 font-medium">{error}</p>}

              <div className="flex gap-3 pt-2">
                <button type="button" onClick={closeModals} className="flex-1 px-4 py-2 border border-slate-200 text-slate-600 rounded-lg hover:bg-slate-50 font-medium text-sm">
                  Cancelar
                </button>
                <button 
                  type="submit" 
                  className={`flex-1 px-4 py-2 text-white rounded-lg font-medium text-sm shadow-md transition-all ${
                    isDefaultPassword 
                      ? 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100' 
                      : 'bg-amber-600 hover:bg-amber-700 shadow-amber-100'
                  }`}
                >
                  {isDefaultPassword ? 'Criar & Estornar' : 'Confirmar Estorno'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

