               <div className="w-12 h-12 bg-slate-100 rounded-md overflow-hidden shrink-0">
                  <img src={item.imageUrl} alt="" className="w-full h-full object-cover" />
               </div>
               <div className="flex-1 min-w-0">
                 <h4 className="text-sm font-medium text-slate-800 truncate">{item.name}</h4>
                 <div className="text-xs text-primary font-bold">R$ {(item.price * item.quantity).toFixed(2)}</div>
               </div>
               <div className="flex items-center gap-2 bg-slate-50 rounded-lg p-1">
                 <button onClick={() => updateCartQuantity(item.id, -1)} className="p-1 hover:bg-white rounded shadow-sm text-slate-600 disabled:opacity-30">
                   <Minus size={14} />
                 </button>
                 <span className="text-xs font-bold w-4 text-center">{item.quantity}</span>
                 <button 
                  onClick={() => updateCartQuantity(item.id, 1)} 
                  disabled={item.quantity >= item.stock} 
                  className="p-1 hover:bg-white rounded shadow-sm text-slate-600 disabled:opacity-30 disabled:cursor-not-allowed"
                  title={item.quantity >= item.stock ? "Estoque insuficiente" : "Adicionar mais um"}
                 >
                   <Plus size={14} />
                 </button>
               </div>
               <button onClick={() => removeFromCart(item.id)} className="text-red-400 hover:text-red-500 p-1">
                 <Trash2 size={16} />
               </button>
            </div>
          ))}
          {cart.length === 0 && (
            <div className="h-full flex flex-col items-center justify-center text-slate-400 opacity-60">
              <div className="w-16 h-16 border-2 border-dashed border-slate-300 rounded-full flex items-center justify-center mb-2">
                <Search size={24} />
              </div>
              <p className="text-sm">Seu carrinho está vazio</p>
            </div>
          )}
        </div>

        {/* Footer / Payment */}
        <div className="p-4 bg-slate-50 border-t border-slate-200 space-y-4">
          <div className="flex justify-between items-center text-lg font-bold text-slate-800">
            <span>Total</span>
            <span>R$ {cartTotal.toFixed(2)}</span>
          </div>

          <div className="grid grid-cols-3 gap-2">
             <button 
               onClick={() => completeSale('credit')}
               disabled={cart.length === 0}
               className="flex flex-col items-center justify-center gap-1 p-3 bg-white border border-slate-200 rounded-xl hover:bg-primary hover:text-white hover:border-primary transition-colors disabled:opacity-50"
             >
               <CreditCard size={20} />
               <span className="text-xs font-medium">Cartão</span>
             </button>
             <button 
               onClick={() => completeSale('cash')}
               disabled={cart.length === 0}
               className="flex flex-col items-center justify-center gap-1 p-3 bg-white border border-slate-200 rounded-xl hover:bg-green-600 hover:text-white hover:border-green-600 transition-colors disabled:opacity-50"
             >
               <Banknote size={20} />
               <span className="text-xs font-medium">Dinheiro</span>
             </button>
             <button 
               onClick={() => completeSale('pix')}
               disabled={cart.length === 0}
               className="flex flex-col items-center justify-center gap-1 p-3 bg-white border border-slate-200 rounded-xl hover:bg-teal-500 hover:text-white hover:border-teal-500 transition-colors disabled:opacity-50"
             >
