              <h3 className={`font-bold flex items-center gap-2 ${isDefaultPassword ? 'text-indigo-700' : 'text-red-700'}`}>
                {isDefaultPassword ? <ShieldCheck size={18} /> : <AlertTriangle size={18} />}
                {isDefaultPassword ? 'Segurança: Criar Nova Senha' : 'Limpar Histórico'}
              </h3>
              <button onClick={closeModals} className="text-slate-400 hover:text-slate-600">
                <X size={20} />
              </button>
            </div>

            <form onSubmit={handleClearHistory} className="p-6 space-y-4">
              <div className={`p-3 rounded-lg text-sm ${isDefaultPassword ? 'bg-indigo-50 text-indigo-700 border border-indigo-100' : 'bg-red-50 text-red-700 border border-red-100'}`}>
                {isDefaultPassword 
                  ? "Para sua segurança, defina uma senha personalizada antes de limpar seu histórico de vendas pela primeira vez." 
                  : "Esta ação apagará permanentemente todos os registros de vendas passadas."
                }
              </div>

              {/* Scope Confirmation Info */}
              <div className="flex gap-2 items-start p-3 bg-slate-50 rounded-lg text-xs text-slate-500 border border-slate-200">
                <Info size={14} className="shrink-0 mt-0.5" />
                <p>Nota: Esta ação **NÃO** altera o estoque ou os produtos. Apenas o registro de logs será removido.</p>
              </div>

              {isDefaultPassword ? (
                <>
                  <div className="space-y-2">
                    <label className="text-xs font-bold text-slate-500 uppercase flex items-center gap-1">
                      <Key size={12} /> Nova Senha Admin
                    </label>
                    <input 
                      autoFocus
                      type="password" 
                      value={password}
                      onChange={e => setPassword(e.target.value)}
                      className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                      placeholder="Mínimo 4 caracteres..."
                      required
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-xs font-bold text-slate-500 uppercase">Confirmar Nova Senha</label>
                    <input 
                      type="password" 
                      value={confirmPassword}
