              />
            </div>
            <div className="text-xs font-bold text-slate-400 uppercase">até hoje</div>
          </div>
        )}
      </div>

      <div className="space-y-4">
        {filteredSales.map(sale => {
          const isCanceled = sale.status === 'canceled';

          return (
            <div 
              key={sale.id} 
              className={`bg-white border ${isCanceled ? 'border-red-100 opacity-75' : 'border-slate-100'} rounded-xl p-4 shadow-sm hover:shadow-md transition-shadow flex flex-col lg:flex-row gap-4 items-start lg:items-center relative overflow-hidden`}
            >
              {isCanceled && (
