                  <p className={`text-lg font-bold ${isCanceled ? 'text-slate-400 line-through' : 'text-emerald-600'}`}>R$ {sale.total.toFixed(2)}</p>
                </div>

                {!isCanceled && (
                  <button 
                    onClick={() => setSaleToCancel(sale.id)}
                    className="p-2 text-amber-600 hover:bg-amber-50 rounded-lg transition-colors group relative"
                    title="Estornar Venda"
                  >
                    <RotateCcw size={18} />
                  </button>
                )}
              </div>
            </div>
          );
        })}

        {filteredSales.length === 0 && (
          <div className="text-center py-16 bg-white rounded-2xl border border-dashed border-slate-200 flex flex-col items-center justify-center">
            <div className="p-4 bg-slate-50 rounded-full mb-4">
              <Clock size={32} className="text-slate-300" />
            </div>
            <p className="text-slate-500 font-medium">Nenhum registro encontrado neste período.</p>
            {filterMode === '24h' && (
              <button 
                onClick={() => setFilterMode('custom')}
                className="mt-4 text-primary text-sm font-bold hover:underline"
              >
