      {/* Clear History Modal */}
      {showClearModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/40 backdrop-blur-sm animate-fade-in">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-sm overflow-hidden">
            <div className={`p-4 border-b border-slate-100 flex justify-between items-center ${isDefaultPassword ? 'bg-indigo-50' : 'bg-red-50'}`}>
              <h3 className={`font-bold flex items-center gap-2 ${isDefaultPassword ? 'text-indigo-700' : 'text-red-700'}`}>
