import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { Product, Sale, CartItem } from '../types';
import { INITIAL_PRODUCTS } from '../constants';

interface StoreContextType {
  products: Product[];
  sales: Sale[];
  cart: CartItem[];
  allTimeStats: { revenue: number; salesCount: number };
  isDefaultPassword: boolean;
  addProduct: (product: Product) => void;
  updateProduct: (product: Product) => void;
  deleteProduct: (id: string) => void;
  addToCart: (product: Product) => void;
  removeFromCart: (productId: string) => void;
  updateCartQuantity: (productId: string, delta: number) => void;
  clearCart: () => void;
  completeSale: (paymentMethod: Sale['paymentMethod']) => void;
  cancelSale: (saleId: string, password: string) => { success: boolean; message: string };
  clearSalesHistory: (password: string) => boolean;
  importData: (data: any, password: string) => boolean;
  resetSystem: (password: string) => boolean;
  updateAdminPassword: (currentPw: string, newPw: string) => boolean;
}

const StoreContext = createContext<StoreContextType | undefined>(undefined);

export const StoreProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('smartpos_products');
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });

  const [sales, setSales] = useState<Sale[]>(() => {
    const saved = localStorage.getItem('smartpos_sales');
    return saved ? JSON.parse(saved) : [];
  });

  // Estatísticas acumuladas que não são perdidas ao limpar o histórico
  const [allTimeStats, setAllTimeStats] = useState(() => {
    const saved = localStorage.getItem('smartpos_alltime_stats');
    return saved ? JSON.parse(saved) : { revenue: 0, salesCount: 0 };
  });

  const [cart, setCart] = useState<CartItem[]>([]);

  const [adminPassword, setAdminPassword] = useState<string>(() => {
    return localStorage.getItem('smartpos_password') || 'admin';
  });

  const isDefaultPassword = adminPassword === 'admin';

  useEffect(() => {
    localStorage.setItem('smartpos_products', JSON.stringify(products));
  }, [products]);

  useEffect(() => {
    localStorage.setItem('smartpos_sales', JSON.stringify(sales));
  }, [sales]);

  useEffect(() => {
    localStorage.setItem('smartpos_alltime_stats', JSON.stringify(allTimeStats));
  }, [allTimeStats]);

  useEffect(() => {
    localStorage.setItem('smartpos_password', adminPassword);
  }, [adminPassword]);

  const addProduct = (product: Product) => setProducts(prev => [...prev, product]);

  const updateProduct = (updatedProduct: Product) => {
    setProducts(prev => prev.map(p => p.id === updatedProduct.id ? updatedProduct : p));
  };

  const deleteProduct = (id: string) => setProducts(prev => prev.filter(p => p.id !== id));

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      const currentProduct = products.find(p => p.id === product.id);
      const availableStock = currentProduct ? currentProduct.stock : 0;

      if (existing) {
        if (existing.quantity < availableStock) {
          return prev.map(item => 
            item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item
          );
        }
        return prev;
      }

      if (availableStock > 0) {
        return [...prev, { ...product, quantity: 1 }];
      }
      return prev;
    });
  };

  const removeFromCart = (productId: string) => {
    setCart(prev => prev.filter(item => item.id !== productId));
  };

  const updateCartQuantity = (productId: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === productId) {
        const currentProduct = products.find(p => p.id === productId);
        const availableStock = currentProduct ? currentProduct.stock : 0;
        const newQty = item.quantity + delta;

        if (newQty > 0 && newQty <= availableStock) {
          return { ...item, quantity: newQty };
        }
      }
      return item;
    }));
  };

  const clearCart = () => setCart([]);

  const completeSale = (paymentMethod: Sale['paymentMethod']) => {
    const total = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

    // Gerar ID sequencial baseado no total de vendas histórico + 1
    const nextSequentialId = allTimeStats.salesCount + 1;

    const newSale: Sale = {
      id: nextSequentialId.toString(),
      timestamp: Date.now(),
      total,
      items: [...cart],
      paymentMethod,
      status: 'completed'
    };

    setSales(prev => [newSale, ...prev]);

    // Atualiza as estatísticas globais que persistem após a limpeza de histórico
    setAllTimeStats(prev => ({
      revenue: prev.revenue + total,
      salesCount: prev.salesCount + 1
    }));

    setProducts(prev => prev.map(p => {
      const cartItem = cart.find(c => c.id === p.id);
      if (cartItem) {
        return { ...p, stock: Math.max(0, p.stock - cartItem.quantity) };
      }
      return p;
    }));

    clearCart();
  };

  const cancelSale = (saleId: string, password: string) => {
    if (password !== adminPassword) {
      return { success: false, message: 'Senha incorreta.' };
    }

    const saleIndex = sales.findIndex(s => s.id === saleId);
    if (saleIndex === -1) return { success: false, message: 'Venda não encontrada.' };
    if (sales[saleIndex].status === 'canceled') return { success: false, message: 'Venda já foi cancelada.' };

    const saleToCancel = sales[saleIndex];

    const updatedSales = [...sales];
    updatedSales[saleIndex] = { ...saleToCancel, status: 'canceled' };
    setSales(updatedSales);

    // Deduz do faturamento acumulado já que foi estornado
    setAllTimeStats(prev => ({
      revenue: Math.max(0, prev.revenue - saleToCancel.total),
      salesCount: Math.max(0, prev.salesCount - 1)
    }));

    setProducts(prev => prev.map(p => {
      const itemToReturn = saleToCancel.items.find(item => item.id === p.id);
      if (itemToReturn) {
        return { ...p, stock: p.stock + itemToReturn.quantity };
      }
      return p;
    }));

    return { success: true, message: 'Venda estornada com sucesso. Estoque reposto.' };
  };

  const validatePassword = (password: string): boolean => password === adminPassword;

  const updateAdminPassword = (currentPw: string, newPw: string): boolean => {
    if (validatePassword(currentPw)) {
      setAdminPassword(newPw);
      return true;
    }
    return false;
  };

  const clearSalesHistory = (password: string): boolean => {
    if (validatePassword(password)) {
      setSales([]); // Limpa apenas a lista visual
      // Nota: allTimeStats NÃO são resetados aqui.
      return true;
    }
    return false;
  };

  const importData = (data: any, password: string): boolean => {
    if (!validatePassword(password)) return false;
    if (data.products) setProducts(data.products);
    if (data.sales) setSales(data.sales);
    if (data.allTimeStats) setAllTimeStats(data.allTimeStats);
    return true;
  };

  const resetSystem = (password: string): boolean => {
    if (!validatePassword(password)) return false;
    setProducts(INITIAL_PRODUCTS);
    setSales([]);
    setCart([]);
    setAllTimeStats({ revenue: 0, salesCount: 0 }); // Reset de fábrica reseta tudo
    return true;
  };

  return (
    <StoreContext.Provider value={{
      products,
      sales,
      cart,
      allTimeStats,
      isDefaultPassword,
      addProduct,
      updateProduct,
      deleteProduct,
      addToCart,
      removeFromCart,
      updateCartQuantity,
      clearCart,
      completeSale,
      cancelSale,
      clearSalesHistory,
      importData,
      resetSystem,
      updateAdminPassword
    }}>
      {children}
    </StoreContext.Provider>
  );
};

export const useStore = () => {
  const context = useContext(StoreContext);
  if (!context) throw new Error('useStore must be used within a StoreProvider');
  return context;
};

import React, { useState, useMemo } from 'react';
import { useStore } from '../context/StoreContext';
import { Clock, CreditCard, Banknote, QrCode, AlertTriangle, X, RotateCcw, Ban, ShieldCheck, Key, Info, Calendar, Filter, ChevronRight } from 'lucide-react';

export const SalesHistory: React.FC = () => {
  const { sales, cancelSale, isDefaultPassword, updateAdminPassword } = useStore();

  // Modals
  const [saleToCancel, setSaleToCancel] = useState<string | null>(null);

  // Filtering state
  const [filterMode, setFilterMode] = useState<'24h' | 'custom'>('24h');
  const [startDate, setStartDate] = useState<string>(() => {
    const yesterday = new Date();
    yesterday.setDate(yesterday.getDate() - 1);
    return yesterday.toISOString().split('T')[0];
  });

  // Password state
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [error, setError] = useState('');

  // Filtered Sales Logic
  const filteredSales = useMemo(() => {
    const now = Date.now();
    const twentyFourHoursAgo = now - (24 * 60 * 60 * 1000);

    return sales.filter(sale => {
      if (filterMode === '24h') {
        return sale.timestamp >= twentyFourHoursAgo;
      } else {
        // Start date is inclusive (start of the day)
        const selectedStart = new Date(startDate + 'T00:00:00').getTime();
        return sale.timestamp >= selectedStart;
      }
    });
  }, [sales, filterMode, startDate]);

  const getPaymentIcon = (method: string) => {
    switch (method) {
      case 'credit': return <CreditCard size={16} className="text-blue-500" />;
      case 'debit': return <CreditCard size={16} className="text-sky-500" />;
      case 'cash': return <Banknote size={16} className="text-green-500" />;
      case 'pix': return <QrCode size={16} className="text-teal-500" />;
      default: return <CreditCard size={16} />;
    }
  };

  const getPaymentLabel = (method: string) => {
    const labels: Record<string, string> = { credit: 'Cartão de Crédito', debit: 'Débito', cash: 'Dinheiro', pix: 'Pix' };
    return labels[method] || method;
  };

  const handleCancelSale = (e: React.FormEvent) => {
    e.preventDefault();
    if (!saleToCancel) return;
    setError('');

    if (isDefaultPassword) {
      if (password.length < 4) {
        setError('A senha deve ter pelo menos 4 caracteres.');
        return;
      }
      if (password !== confirmPassword) {
        setError('As senhas não conferem.');
        return;
      }

      const result = cancelSale(saleToCancel, 'admin');
      if (result.success) {
        updateAdminPassword('admin', password);
        alert('Venda estornada e nova senha configurada!');
        closeModals();
      } else {
        setError(result.message);
      }
    } else {
      const result = cancelSale(saleToCancel, password);
      if (result.success) {
        closeModals();
        alert(result.message);
      } else {
        setError(result.message);
      }
    }
  };

  const closeModals = () => {
    setSaleToCancel(null);
    setPassword('');
    setConfirmPassword('');
    setError('');
  };

  return (
    <div className="space-y-6 animate-fade-in">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
