          <button 
            onClick={() => setFilterMode('24h')}
            className={`flex-1 md:flex-none px-4 py-1.5 rounded-lg text-sm font-medium transition-all ${
              filterMode === '24h' 
                ? 'bg-white text-primary shadow-sm' 
                : 'text-slate-500 hover:text-slate-700'
            }`}
          >
            Últimas 24 Horas
          </button>
          <button 
