              </h3>
              <button onClick={closeModals} className="text-slate-400 hover:text-slate-600">
                <X size={20} />
              </button>
            </div>

            <form onSubmit={handleCancelSale} className="p-6 space-y-4">
              <div className={`p-3 rounded-lg text-sm ${isDefaultPassword ? 'bg-indigo-50 text-indigo-700 border border-indigo-100' : 'text-slate-600'}`}>
                {isDefaultPassword 
                  ? "Para sua segurança, defina uma senha personalizada antes de realizar o seu primeiro estorno." 
                  : <>Você está estornando o pedido <strong>#{saleToCancel}</strong>. O estoque será reposto.</>
                }
              </div>

              {isDefaultPassword ? (
                <>
                  <div className="space-y-2">
                    <label className="text-xs font-bold text-slate-500 uppercase flex items-center gap-1">
                      <Key size={12} /> Nova Senha Admin
                    </label>
                    <input 
                      autoFocus
                      type="password" 
                      value={password}
                      onChange={e => setPassword(e.target.value)}
                      className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                      placeholder="Escolha uma senha forte..."
                      required
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-xs font-bold text-slate-500 uppercase">Confirmar Nova Senha</label>
                    <input 
                      type="password" 
                      value={confirmPassword}
                      onChange={e => setConfirmPassword(e.target.value)}
                      className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                      placeholder="Repita a senha..."
                      required
                    />
                  </div>
                </>
              ) : (
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-500 uppercase">Senha Admin</label>
                  <input 
                    autoFocus
                    type="password" 
                    value={password}
                    onChange={e => setPassword(e.target.value)}
                    className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-amber-500 focus:outline-none"
                    placeholder="Sua senha secreta..."
                  />
                </div>
              )}

              {error && (
                <div className="flex items-center gap-2 p-2 bg-red-50 text-red-600 rounded-lg text-xs font-medium border border-red-100">
                  <AlertTriangle size={14} />
                  {error}
                </div>
              )}

              <div className="flex gap-3 pt-2">
                <button type="button" onClick={closeModals} className="flex-1 px-4 py-2 border border-slate-200 text-slate-600 rounded-lg hover:bg-slate-50 font-medium text-sm">
                  Cancelar
                </button>
                <button 
                  type="submit" 
                  className={`flex-1 px-4 py-2 text-white rounded-lg font-medium text-sm shadow-md transition-all active:scale-95 ${
                    isDefaultPassword 
                      ? 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100' 
                      : 'bg-amber-600 hover:bg-amber-700 shadow-amber-100'
                  }`}
                >
                  {isDefaultPassword ? 'Definir & Estornar' : 'Confirmar Estorno'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { Product, Sale, CartItem } from '../types';
import { INITIAL_PRODUCTS } from '../constants';

interface StoreContextType {
  products: Product[];
  sales: Sale[];
  cart: CartItem[];
  allTimeStats: { revenue: number; salesCount: number };
  isDefaultPassword: boolean;
  addProduct: (product: Product) => void;
  updateProduct: (product: Product) => void;
  deleteProduct: (id: string) => void;
  addToCart: (product: Product) => void;
  removeFromCart: (productId: string) => void;
  updateCartQuantity: (productId: string, delta: number) => void;
  clearCart: () => void;
  completeSale: (paymentMethod: Sale['paymentMethod']) => void;
  cancelSale: (saleId: string, password: string) => { success: boolean; message: string };
  clearSalesHistory: (password: string) => boolean;
  importData: (data: any, password: string) => boolean;
  resetSystem: (password: string) => boolean;
  updateAdminPassword: (currentPw: string, newPw: string) => boolean;
}

const StoreContext = createContext<StoreContextType | undefined>(undefined);

export const StoreProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('smartpos_products');
    return saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
  });

  const [sales, setSales] = useState<Sale[]>(() => {
    const saved = localStorage.getItem('smartpos_sales');
    return saved ? JSON.parse(saved) : [];
  });

  const [allTimeStats, setAllTimeStats] = useState(() => {
    const saved = localStorage.getItem('smartpos_alltime_stats');
    return saved ? JSON.parse(saved) : { revenue: 0, salesCount: 0 };
  });

  const [cart, setCart] = useState<CartItem[]>([]);

  const [adminPassword, setAdminPassword] = useState<string>(() => {
    return localStorage.getItem('smartpos_password') || 'admin';
  });

  const isDefaultPassword = adminPassword === 'admin';

  useEffect(() => {
    localStorage.setItem('smartpos_products', JSON.stringify(products));
  }, [products]);

  useEffect(() => {
    localStorage.setItem('smartpos_sales', JSON.stringify(sales));
  }, [sales]);

  useEffect(() => {
    localStorage.setItem('smartpos_alltime_stats', JSON.stringify(allTimeStats));
  }, [allTimeStats]);

  useEffect(() => {
    localStorage.setItem('smartpos_password', adminPassword);
  }, [adminPassword]);

  const addProduct = (product: Product) => setProducts(prev => [...prev, product]);

  const updateProduct = (updatedProduct: Product) => {
    setProducts(prev => prev.map(p => p.id === updatedProduct.id ? updatedProduct : p));
  };

  const deleteProduct = (id: string) => setProducts(prev => prev.filter(p => p.id !== id));

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      const currentProduct = products.find(p => p.id === product.id);
      const availableStock = currentProduct ? currentProduct.stock : 0;

      if (existing) {
        if (existing.quantity < availableStock) {
          return prev.map(item => 
            item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item
          );
        }
        return prev;
      }

      if (availableStock > 0) {
        return [...prev, { ...product, quantity: 1 }];
      }
      return prev;
    });
  };

  const removeFromCart = (productId: string) => {
    setCart(prev => prev.filter(item => item.id !== productId));
  };

  const updateCartQuantity = (productId: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === productId) {
        const currentProduct = products.find(p => p.id === productId);
        const availableStock = currentProduct ? currentProduct.stock : 0;
        const newQty = item.quantity + delta;

        if (newQty > 0 && newQty <= availableStock) {
          return { ...item, quantity: newQty };
        }
      }
      return item;
    }));
  };

  const clearCart = () => setCart([]);

  const completeSale = (paymentMethod: Sale['paymentMethod']) => {
    const total = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);

    // Gerar ID sequencial formatado (ex: 0001)
    const nextSequentialId = allTimeStats.salesCount + 1;
    const formattedId = nextSequentialId.toString().padStart(4, '0');

    const newSale: Sale = {
      id: formattedId,
      timestamp: Date.now(),
      total,
      items: [...cart],
      paymentMethod,
      status: 'completed'
    };

    setSales(prev => [newSale, ...prev]);

    setAllTimeStats(prev => ({
      revenue: prev.revenue + total,
      salesCount: prev.salesCount + 1
    }));

    setProducts(prev => prev.map(p => {
      const cartItem = cart.find(c => c.id === p.id);
      if (cartItem) {
        return { ...p, stock: Math.max(0, p.stock - cartItem.quantity) };
      }
      return p;
    }));

    clearCart();
  };

  const cancelSale = (saleId: string, password: string) => {
    if (password !== adminPassword) {
      return { success: false, message: 'Senha incorreta.' };
    }

    const saleIndex = sales.findIndex(s => s.id === saleId);
    if (saleIndex === -1) return { success: false, message: 'Venda não encontrada.' };
    if (sales[saleIndex].status === 'canceled') return { success: false, message: 'Venda já foi cancelada.' };

    const saleToCancel = sales[saleIndex];

    const updatedSales = [...sales];
    updatedSales[saleIndex] = { ...saleToCancel, status: 'canceled' };
    setSales(updatedSales);

    // Nota: O salesCount histórico não é reduzido para manter a sequência de IDs correta
    setAllTimeStats(prev => ({
      ...prev,
      revenue: Math.max(0, prev.revenue - saleToCancel.total),
    }));

    setProducts(prev => prev.map(p => {
      const itemToReturn = saleToCancel.items.find(item => item.id === p.id);
      if (itemToReturn) {
        return { ...p, stock: p.stock + itemToReturn.quantity };
      }
      return p;
    }));

    return { success: true, message: 'Venda estornada com sucesso. Estoque reposto.' };
  };

  const validatePassword = (password: string): boolean => password === adminPassword;

  const updateAdminPassword = (currentPw: string, newPw: string): boolean => {
    if (validatePassword(currentPw)) {
      setAdminPassword(newPw);
      return true;
    }
    return false;
  };

  const clearSalesHistory = (password: string): boolean => {
    if (validatePassword(password)) {
      setSales([]);
      return true;
    }
    return false;
  };

  const importData = (data: any, password: string): boolean => {
    if (!validatePassword(password)) return false;
    if (data.products) setProducts(data.products);
    if (data.sales) setSales(data.sales);
    if (data.allTimeStats) setAllTimeStats(data.allTimeStats);
    return true;
  };

  const resetSystem = (password: string): boolean => {
    if (!validatePassword(password)) return false;
    setProducts(INITIAL_PRODUCTS);
    setSales([]);
    setCart([]);
    setAllTimeStats({ revenue: 0, salesCount: 0 });
    return true;
  };

  return (
    <StoreContext.Provider value={{
      products,
      sales,
      cart,
      allTimeStats,
      isDefaultPassword,
      addProduct,
      updateProduct,
      deleteProduct,
      addToCart,
      removeFromCart,
      updateCartQuantity,
      clearCart,
      completeSale,
      cancelSale,
      clearSalesHistory,
      importData,
      resetSystem,
      updateAdminPassword
    }}>
      {children}
    </StoreContext.Provider>
  );
};

export const useStore = () => {
  const context = useContext(StoreContext);
  if (!context) throw new Error('useStore must be used within a StoreProvider');
  return context;
};

import React, { useState, useMemo } from 'react';
import { useStore } from '../context/StoreContext';
import { Product } from '../types';
import { Plus, Search, Edit2, Trash2, X, Box, Image as ImageIcon, Filter, ChevronDown, ChevronUp } from 'lucide-react';

type StockStatus = 'all' | 'out_of_stock' | 'low_stock' | 'normal';

export const Inventory: React.FC = () => {
  const { products, deleteProduct, addProduct, updateProduct } = useStore();

  // States
  const [searchTerm, setSearchTerm] = useState('');
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [showFilters, setShowFilters] = useState(false);

  // Advanced Filter States
  const [selectedCategory, setSelectedCategory] = useState<string>('all');
  const [stockStatus, setStockStatus] = useState<StockStatus>('all');
  const [minPrice, setMinPrice] = useState<string>('');
  const [maxPrice, setMaxPrice] = useState<string>('');

  // Calculate unique categories
  const categories = useMemo(() => {
    return Array.from(new Set(products.map(p => p.category))).sort();
  }, [products]);

  // Form State
  const [formData, setFormData] = useState<Partial<Product>>({
    name: '', category: '', price: 0, stock: 0, description: '', imageUrl: ''
  });
  const [isEditing, setIsEditing] = useState(false);

  const handleOpenModal = (product?: Product) => {
    if (product) {
      setFormData(product);
      setIsEditing(true);
    } else {
      setFormData({
        name: '', category: '', price: 0, stock: 0, description: '', imageUrl: ''
      });
      setIsEditing(false);
    }
    setIsModalOpen(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name || !formData.price || !formData.category) return;

    const productToSave = {
      ...formData,
      id: isEditing ? formData.id! : Date.now().toString(),
      price: Number(formData.price),
      stock: Number(formData.stock),
      imageUrl: formData.imageUrl || 'https://placehold.co/200x200?text=Sem+Imagem',
    } as Product;

    if (isEditing) {
      updateProduct(productToSave);
    } else {
      addProduct(productToSave);
    }
    setIsModalOpen(false);
  };

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      // Search Term
      const matchesSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase()) || 
                           p.category.toLowerCase().includes(searchTerm.toLowerCase());

      // Category
      const matchesCategory = selectedCategory === 'all' || p.category === selectedCategory;

      // Stock Status
      let matchesStock = true;
      if (stockStatus === 'out_of_stock') matchesStock = p.stock === 0;
      else if (stockStatus === 'low_stock') matchesStock = p.stock > 0 && p.stock < 5;
      else if (stockStatus === 'normal') matchesStock = p.stock >= 5;

      // Price Range
      const min = minPrice === '' ? 0 : parseFloat(minPrice);
      const max = maxPrice === '' ? Infinity : parseFloat(maxPrice);
      const matchesPrice = p.price >= min && p.price <= max;

      return matchesSearch && matchesCategory && matchesStock && matchesPrice;
    });
  }, [products, searchTerm, selectedCategory, stockStatus, minPrice, maxPrice]);

  const clearFilters = () => {
    setSearchTerm('');
    setSelectedCategory('all');
    setStockStatus('all');
    setMinPrice('');
    setMaxPrice('');
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Gestão de Estoque</h2>
          <p className="text-slate-500">Adicione, edite ou remova produtos e gerencie seus níveis.</p>
        </div>
        <button 
          onClick={() => handleOpenModal()}
          className="flex items-center gap-2 bg-primary text-white px-4 py-2 rounded-xl hover:bg-emerald-600 transition-colors shadow-sm"
        >
          <Plus size={20} />
          <span>Novo Produto</span>
        </button>
      </div>

      <div className="bg-white rounded-2xl shadow-sm border border-slate-100 overflow-hidden">
        {/* Filter Bar Header */}
        <div className="p-4 border-b border-slate-100 flex flex-col md:flex-row gap-4 items-center justify-between bg-slate-50/50">
          <div className="relative w-full md:max-w-md">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={18} />
            <input 
              type="text" 
              placeholder="Buscar por nome ou categoria..." 
              className="w-full pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary/20 focus:border-primary transition-all text-sm"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>

          <div className="flex items-center gap-2 w-full md:w-auto">
            <button 
              onClick={() => setShowFilters(!showFilters)}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg text-sm font-medium border transition-all ${
                showFilters 
                ? 'bg-primary/10 border-primary text-primary' 
                : 'bg-white border-slate-200 text-slate-600 hover:border-slate-300'
              }`}
            >
              <Filter size={16} />
              <span>Filtros Avançados</span>
              {showFilters ? <ChevronUp size={14} /> : <ChevronDown size={14} />}
            </button>

            {(selectedCategory !== 'all' || stockStatus !== 'all' || minPrice !== '' || maxPrice !== '' || searchTerm !== '') && (
              <button 
                onClick={clearFilters}
                className="text-xs font-bold text-slate-400 hover:text-red-500 transition-colors underline decoration-dotted underline-offset-4"
              >
                Limpar Tudo
              </button>
            )}
          </div>
        </div>

        {/* Expandable Advanced Filters */}
        {showFilters && (
          <div className="p-4 border-b border-slate-100 bg-slate-50/30 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 animate-fade-in">
            <div className="space-y-1.5">
              <label className="text-[10px] font-bold text-slate-400 uppercase tracking-wider">Categoria</label>
              <select 
                className="w-full p-2 bg-white border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-primary/20"
                value={selectedCategory}
                onChange={(e) => setSelectedCategory(e.target.value)}
              >
                <option value="all">Todas as Categorias</option>
                {categories.map(cat => (
                  <option key={cat} value={cat}>{cat}</option>
                ))}
              </select>
            </div>

            <div className="space-y-1.5">
              <label className="text-[10px] font-bold text-slate-400 uppercase tracking-wider">Status do Estoque</label>
              <select 
                className="w-full p-2 bg-white border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-primary/20"
                value={stockStatus}
                onChange={(e) => setStockStatus(e.target.value as StockStatus)}
              >
                <option value="all">Todos os Status</option>
                <option value="out_of_stock">Esgotado (0)</option>
                <option value="low_stock">Estoque Baixo (1-4)</option>
                <option value="normal">Estoque Normal (5+)</option>
              </select>
            </div>

            <div className="space-y-1.5 sm:col-span-2">
              <label className="text-[10px] font-bold text-slate-400 uppercase tracking-wider">Faixa de Preço (R$)</label>
              <div className="flex items-center gap-2">
                <input 
                  type="number" 
                  placeholder="Min" 
                  className="w-full p-2 bg-white border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-primary/20"
                  value={minPrice}
                  onChange={(e) => setMinPrice(e.target.value)}
                />
                <span className="text-slate-400">a</span>
                <input 
                  type="number" 
                  placeholder="Max" 
                  className="w-full p-2 bg-white border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-primary/20"
                  value={maxPrice}
                  onChange={(e) => setMaxPrice(e.target.value)}
                />
              </div>
            </div>
          </div>
        )}

        {/* Results Table */}
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm text-slate-600">
            <thead className="bg-slate-50/80 text-slate-800 font-semibold border-b border-slate-200 uppercase tracking-wider text-[11px]">
              <tr>
                <th className="p-4 w-20">Imagem</th>
                <th className="p-4">Produto</th>
                <th className="p-4">Categoria</th>
                <th className="p-4">Preço</th>
                <th className="p-4">Estoque</th>
                <th className="p-4 text-right">Ações</th>
              </tr>
