            <tbody className="divide-y divide-slate-100">
              {filteredProducts.map(product => {
                const isOutOfStock = product.stock === 0;
                const isLowStock = product.stock > 0 && product.stock < 5;

                return (
                  <tr key={product.id} className="hover:bg-slate-50/50 transition-colors group">
                    <td className="p-4">
                      <img src={product.imageUrl} alt="" className="w-12 h-12 rounded-lg object-cover bg-slate-100 border border-slate-100" />
                    </td>
                    <td className="p-4">
                      <p className="font-bold text-slate-800 group-hover:text-primary transition-colors">{product.name}</p>
                      <p className="text-xs text-slate-400 truncate max-w-[200px] font-medium">{product.description || 'Sem descrição'}</p>
