  const [loadingAi, setLoadingAi] = useState(false);

  const activeSales = useMemo(() => sales.filter(s => s.status !== 'canceled'), [sales]);

  const fetchInsight = async () => {
    setLoadingAi(true);
    try {
      const insight = await getBusinessInsights(products, sales, "Analise meu estoque e vendas recentes. O que devo priorizar hoje?");
      setAiInsight(insight);
    } catch (err) {
      setAiInsight("Não foi possível carregar os insights no momento.");
    } finally {
      setLoadingAi(false);
    }
  };

  useEffect(() => {
    fetchInsight();
  }, []);

  const totalRevenue = allTimeStats.revenue;
  const totalSalesCount = allTimeStats.salesCount;
  const lowStockProducts = products.filter(p => p.stock < 5);

  const salesData = activeSales.slice(0, 7).reverse().map(sale => ({
    name: new Date(sale.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
    valor: sale.total
  }));

  const topProducts = useMemo(() => {
    const productCounts: Record<string, number> = {};
    activeSales.forEach(sale => {
