                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { useStore } from '../context/StoreContext';
import { Clock, CreditCard, Banknote, QrCode, AlertTriangle, X, RotateCcw, Ban, ShieldCheck, Key, Info, Calendar, Filter, ChevronRight, FileDown } from 'lucide-react';

export const SalesHistory: React.FC = () => {
  const { sales, cancelSale, isDefaultPassword, updateAdminPassword, exportSalesToCSV } = useStore();

  // Modals
  const [saleToCancel, setSaleToCancel] = useState<string | null>(null);

  // Filtering state
  const [filterMode, setFilterMode] = useState<'24h' | 'custom'>('24h');
  const [startDate, setStartDate] = useState<string>(() => {
    const yesterday = new Date();
    yesterday.setDate(yesterday.getDate() - 1);
    return yesterday.toISOString().split('T')[0];
  });

  // Password state
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [error, setError] = useState('');

  // Filtered Sales Logic
  const filteredSales = useMemo(() => {
    const now = Date.now();
    const twentyFourHoursAgo = now - (24 * 60 * 60 * 1000);

    return sales.filter(sale => {
      if (filterMode === '24h') {
        return sale.timestamp >= twentyFourHoursAgo;
      } else {
        const selectedStart = new Date(startDate + 'T00:00:00').getTime();
        return sale.timestamp >= selectedStart;
      }
    });
  }, [sales, filterMode, startDate]);

  const getPaymentIcon = (method: string) => {
    switch (method) {
      case 'credit': return <CreditCard size={16} className="text-blue-500" />;
      case 'debit': return <CreditCard size={16} className="text-sky-500" />;
      case 'cash': return <Banknote size={16} className="text-green-500" />;
      case 'pix': return <QrCode size={16} className="text-teal-500" />;
      default: return <CreditCard size={16} />;
    }
  };

  const getPaymentLabel = (method: string) => {
    const labels: Record<string, string> = { credit: 'Cartão de Crédito', debit: 'Débito', cash: 'Dinheiro', pix: 'Pix' };
    return labels[method] || method;
  };

  const handleCancelSale = (e: React.FormEvent) => {
    e.preventDefault();
    if (!saleToCancel) return;
    setError('');

    if (isDefaultPassword) {
      if (password.length < 4) {
        setError('A senha deve ter pelo menos 4 caracteres.');
        return;
      }
      if (password !== confirmPassword) {
        setError('As senhas não conferem.');
        return;
      }

      const result = cancelSale(saleToCancel, 'admin');
      if (result.success) {
        updateAdminPassword('admin', password);
        closeModals();
      } else {
        setError(result.message);
      }
    } else {
      const result = cancelSale(saleToCancel, password);
      if (result.success) {
        closeModals();
      } else {
        setError(result.message);
      }
    }
  };

  const closeModals = () => {
    setSaleToCancel(null);
    setPassword('');
    setConfirmPassword('');
    setError('');
  };

  return (
    <div className="space-y-6 animate-fade-in">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Histórico de Vendas</h2>
          <p className="text-slate-500">Gerencie transações e exporte relatórios.</p>
        </div>

        <button 
          onClick={exportSalesToCSV}
          className="flex items-center gap-2 px-4 py-2 bg-slate-800 text-white rounded-xl hover:bg-slate-700 transition-all shadow-sm font-medium"
        >
          <FileDown size={20} />
          <span>Exportar Planilha (CSV)</span>
        </button>
      </header>

      {/* Filter Bar */}
      <div className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm flex flex-col md:flex-row items-center gap-4">
        <div className="flex items-center gap-2 text-slate-500 font-medium text-sm mr-2">
          <Filter size={18} />
          <span>Filtro:</span>
        </div>

        <div className="flex p-1 bg-slate-50 rounded-xl w-full md:w-auto">
          <button 
            onClick={() => setFilterMode('24h')}
            className={`flex-1 md:flex-none px-4 py-1.5 rounded-lg text-sm font-medium transition-all ${
              filterMode === '24h' 
                ? 'bg-white text-primary shadow-sm' 
                : 'text-slate-500 hover:text-slate-700'
            }`}
          >
            Últimas 24 Horas
          </button>
          <button 
            onClick={() => setFilterMode('custom')}
            className={`flex-1 md:flex-none px-4 py-1.5 rounded-lg text-sm font-medium transition-all ${
              filterMode === 'custom' 
                ? 'bg-white text-primary shadow-sm' 
                : 'text-slate-500 hover:text-slate-700'
            }`}
          >
            Personalizado
          </button>
        </div>

        {filterMode === 'custom' && (
          <div className="flex items-center gap-3 w-full md:w-auto animate-fade-in">
            <div className="flex items-center gap-2 text-slate-400">
              <ChevronRight size={16} />
              <span className="text-xs font-bold uppercase">De</span>
            </div>
            <div className="relative flex-1 md:flex-none">
              <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" size={14} />
              <input 
                type="date" 
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
                className="pl-9 pr-3 py-1.5 text-sm bg-slate-50 border border-slate-200 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary focus:border-transparent"
              />
            </div>
          </div>
        )}
      </div>

      <div className="space-y-4">
        {filteredSales.map(sale => {
          const isCanceled = sale.status === 'canceled';

          return (
            <div 
              key={sale.id} 
              className={`bg-white border ${isCanceled ? 'border-red-100 opacity-75' : 'border-slate-100'} rounded-xl p-4 shadow-sm hover:shadow-md transition-shadow flex flex-col lg:flex-row gap-4 items-start lg:items-center relative overflow-hidden`}
            >
              {isCanceled && (
                <div className="absolute top-0 right-0 p-2">
                  <span className="flex items-center gap-1 text-[10px] font-bold uppercase bg-red-100 text-red-600 px-2 py-0.5 rounded-full">
                    <Ban size={10} /> Estornado
                  </span>
                </div>
              )}

              <div className="flex items-center gap-3 w-full lg:w-auto">
                <div className={`w-10 h-10 rounded-full flex items-center justify-center ${isCanceled ? 'bg-red-50 text-red-400' : 'bg-slate-100 text-slate-500'}`}>
                  <Clock size={20} />
                </div>
                <div>
                  <p className={`font-bold ${isCanceled ? 'text-slate-400 line-through' : 'text-slate-800'}`}>Pedido #{sale.id}</p>
                  <p className="text-xs text-slate-500">{new Date(sale.timestamp).toLocaleString('pt-BR')}</p>
                </div>
              </div>

              <div className="flex-1 w-full lg:w-auto space-y-1">
                <div className="flex flex-wrap gap-2">
                  {sale.items.map((item, idx) => (
                    <span key={idx} className={`inline-flex items-center px-2 py-1 border rounded text-xs ${isCanceled ? 'bg-slate-50 border-slate-200 text-slate-400' : 'bg-slate-50 border-slate-200 text-slate-600'}`}>
                      {item.quantity}x {item.name}
                    </span>
                  ))}
                </div>
              </div>

              <div className="flex items-center gap-4 lg:gap-6 w-full lg:w-auto justify-between lg:justify-end border-t lg:border-t-0 pt-3 lg:pt-0">
                <div className="flex items-center gap-2 text-sm text-slate-600 bg-slate-50 px-3 py-1 rounded-lg">
                  {getPaymentIcon(sale.paymentMethod)}
                  <span className="hidden sm:inline">{getPaymentLabel(sale.paymentMethod)}</span>
                </div>

                <div className="text-right min-w-[100px]">
                  <p className="text-xs text-slate-400 font-medium uppercase leading-none mb-1">Total</p>
                  <p className={`text-lg font-bold ${isCanceled ? 'text-slate-400 line-through' : 'text-emerald-600'}`}>R$ {sale.total.toFixed(2)}</p>
                </div>

                {!isCanceled && (
                  <button 
                    onClick={() => setSaleToCancel(sale.id)}
                    className="p-2 text-amber-600 hover:bg-amber-50 rounded-lg transition-colors group relative"
                    title="Estornar Venda"
                  >
                    <RotateCcw size={18} />
                  </button>
                )}
              </div>
            </div>
          );
        })}

        {filteredSales.length === 0 && (
          <div className="text-center py-16 bg-white rounded-2xl border border-dashed border-slate-200 flex flex-col items-center justify-center">
            <div className="p-4 bg-slate-50 rounded-full mb-4">
              <Clock size={32} className="text-slate-300" />
            </div>
            <p className="text-slate-500 font-medium">Nenhum registro encontrado neste período.</p>
          </div>
        )}
      </div>

      {/* Cancel Sale Modal */}
      {saleToCancel && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/40 backdrop-blur-sm animate-fade-in">
          <div className="bg-white rounded-2xl shadow-xl w-full max-w-sm overflow-hidden">
            <div className={`p-4 border-b border-slate-100 flex justify-between items-center ${isDefaultPassword ? 'bg-indigo-50' : 'bg-amber-50'}`}>
              <h3 className={`font-bold flex items-center gap-2 ${isDefaultPassword ? 'text-indigo-700' : 'text-amber-700'}`}>
                {isDefaultPassword ? <ShieldCheck size={18} /> : <RotateCcw size={18} />}
                {isDefaultPassword ? 'Segurança: Criar Nova Senha' : 'Confirmar Estorno'}
              </h3>
              <button onClick={closeModals} className="text-slate-400 hover:text-slate-600">
                <X size={20} />
              </button>
            </div>

            <form onSubmit={handleCancelSale} className="p-6 space-y-4">
              <div className={`p-3 rounded-lg text-sm ${isDefaultPassword ? 'bg-indigo-50 text-indigo-700 border border-indigo-100' : 'text-slate-600'}`}>
                {isDefaultPassword 
                  ? "Para sua segurança, defina uma senha personalizada antes de realizar o seu primeiro estorno." 
                  : <>Você está estornando o pedido <strong>#{saleToCancel}</strong>. O estoque será reposto.</>
                }
              </div>

              {isDefaultPassword ? (
                <>
                  <div className="space-y-2">
                    <label className="text-xs font-bold text-slate-500 uppercase flex items-center gap-1">
                      <Key size={12} /> Nova Senha Admin
                    </label>
                    <input 
                      autoFocus
                      type="password" 
                      value={password}
                      onChange={e => setPassword(e.target.value)}
                      className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                      placeholder="Escolha uma senha forte..."
                      required
                    />
                  </div>
                  <div className="space-y-2">
                    <label className="text-xs font-bold text-slate-500 uppercase">Confirmar Nova Senha</label>
                    <input 
                      type="password" 
                      value={confirmPassword}
                      onChange={e => setConfirmPassword(e.target.value)}
                      className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 focus:outline-none"
                      placeholder="Repita a senha..."
                      required
                    />
                  </div>
                </>
              ) : (
                <div className="space-y-2">
                  <label className="text-xs font-bold text-slate-500 uppercase">Senha Admin</label>
                  <input 
                    autoFocus
                    type="password" 
                    value={password}
                    onChange={e => setPassword(e.target.value)}
                    className="w-full px-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-amber-500 focus:outline-none"
                    placeholder="Sua senha secreta..."
                  />
                </div>
              )}

              {error && (
                <div className="flex items-center gap-2 p-2 bg-red-50 text-red-600 rounded-lg text-xs font-medium border border-red-100">
                  <AlertTriangle size={14} />
                  {error}
                </div>
              )}

              <div className="flex gap-3 pt-2">
                <button type="button" onClick={closeModals} className="flex-1 px-4 py-2 border border-slate-200 text-slate-600 rounded-lg hover:bg-slate-50 font-medium text-sm">
                  Cancelar
                </button>
                <button 
                  type="submit" 
                  className={`flex-1 px-4 py-2 text-white rounded-lg font-medium text-sm shadow-md transition-all active:scale-95 ${
                    isDefaultPassword 
                      ? 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-100' 
                      : 'bg-amber-600 hover:bg-amber-700 shadow-amber-100'
                  }`}
                >
                  {isDefaultPassword ? 'Definir & Estornar' : 'Confirmar'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState } from 'react';
import { StoreProvider, useStore } from './context/StoreContext';
import { Sidebar } from './components/Sidebar';
import { Dashboard } from './components/Dashboard';
import { POS } from './components/POS';
import { Inventory } from './components/Inventory';
import { SalesHistory } from './components/SalesHistory';
import { Settings } from './components/Settings';
import { ViewState } from './types';
import { X, CheckCircle, AlertCircle, Info } from 'lucide-react';

const ToastContainer: React.FC = () => {
  const { toasts, removeToast } = useStore();

  return (
    <div className="fixed bottom-6 right-6 z-[100] flex flex-col gap-3 max-w-sm w-full">
      {toasts.map(toast => (
        <div 
          key={toast.id}
          className={`p-4 rounded-2xl shadow-xl border flex items-center gap-3 animate-slide-in bg-white
            ${toast.type === 'success' ? 'border-emerald-100 text-emerald-800' : ''}
            ${toast.type === 'error' ? 'border-red-100 text-red-800' : ''}
            ${toast.type === 'info' ? 'border-blue-100 text-blue-800' : ''}
          `}
        >
          {toast.type === 'success' && <CheckCircle size={20} className="text-emerald-500" />}
          {toast.type === 'error' && <AlertCircle size={20} className="text-red-500" />}
          {toast.type === 'info' && <Info size={20} className="text-blue-500" />}

          <span className="text-sm font-semibold flex-1">{toast.message}</span>

          <button onClick={() => removeToast(toast.id)} className="text-slate-400 hover:text-slate-600">
            <X size={16} />
          </button>
        </div>
      ))}
    </div>
  );
};

const MainContent: React.FC = () => {
  const [currentView, setCurrentView] = useState<ViewState>('dashboard');

  const renderView = () => {
    switch (currentView) {
      case 'dashboard': return <Dashboard />;
      case 'pos': return <POS />;
      case 'inventory': return <Inventory />;
      case 'history': return <SalesHistory />;
      case 'settings': return <Settings />;
      default: return <Dashboard />;
    }
  };

  return (
    <div className="flex min-h-screen bg-slate-50">
      <Sidebar currentView={currentView} setView={setCurrentView} />

      <main className="flex-1 ml-20 lg:ml-64 p-4 lg:p-8 transition-all duration-300">
        <div className="max-w-7xl mx-auto h-full">
          {renderView()}
        </div>
      </main>

      <ToastContainer />
    </div>
  );
};

const App: React.FC = () => {
  return (
    <StoreProvider>
      <MainContent />
    </StoreProvider>
  );
};

export default App;

import React, { useMemo } from 'react';
import { useStore } from '../context/StoreContext';
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { DollarSign, ShoppingBag, AlertTriangle, TrendingUp, Trophy } from 'lucide-react';

export const Dashboard: React.FC = () => {
  const { products, sales, allTimeStats } = useStore();

  const activeSales = useMemo(() => sales.filter(s => s.status !== 'canceled'), [sales]);

  const totalRevenue = allTimeStats.revenue;
  const totalSalesCount = allTimeStats.salesCount;
  const lowStockProducts = products.filter(p => p.stock < 5);

  const salesData = activeSales.slice(0, 7).reverse().map(sale => ({
    name: new Date(sale.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }),
    valor: sale.total
  }));

  const topProducts = useMemo(() => {
    const productCounts: Record<string, number> = {};
    activeSales.forEach(sale => {
      sale.items.forEach(item => {
        productCounts[item.id] = (productCounts[item.id] || 0) + item.quantity;
      });
    });

    return Object.entries(productCounts)
      .sort(([, a], [, b]) => b - a)
      .slice(0, 5)
      .map(([id, count]) => {
        const product = products.find(p => p.id === id);
        return product ? { ...product, soldCount: count } : null;
      })
      .filter((item): item is (typeof products[0] & { soldCount: number }) => item !== null);
  }, [activeSales, products]);

  return (
    <div className="space-y-6 animate-fade-in">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 border-b border-slate-100 pb-6">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Visão Geral</h2>
          <p className="text-slate-500">Acompanhe o desempenho do seu negócio em tempo real.</p>
        </div>
      </header>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-4">
          <div className="p-3 bg-emerald-100 text-emerald-600 rounded-full">
            <DollarSign size={24} />
          </div>
          <div>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-wider">Faturamento Total</p>
            <p className="text-2xl font-bold text-slate-800">R$ {totalRevenue.toFixed(2)}</p>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-4">
          <div className="p-3 bg-blue-100 text-blue-600 rounded-full">
            <ShoppingBag size={24} />
          </div>
          <div>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-wider">Vendas Totais</p>
            <p className="text-2xl font-bold text-slate-800">{totalSalesCount}</p>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-4 relative">
          {lowStockProducts.length > 0 && (
            <span className="absolute top-4 right-4 flex h-3 w-3">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>
              <span className="relative inline-flex rounded-full h-3 w-3 bg-red-500"></span>
            </span>
          )}
          <div className="p-3 bg-amber-100 text-amber-600 rounded-full">
            <AlertTriangle size={24} />
          </div>
          <div>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-wider">Itens em Alerta</p>
            <p className="text-2xl font-bold text-slate-800">{lowStockProducts.length}</p>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex items-center gap-4">
          <div className="p-3 bg-purple-100 text-purple-600 rounded-full">
            <TrendingUp size={24} />
          </div>
          <div>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-wider">Ticket Médio</p>
            <p className="text-2xl font-bold text-slate-800">
              R$ {(totalSalesCount > 0 ? totalRevenue / totalSalesCount : 0).toFixed(2)}
            </p>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold text-slate-800 mb-6 flex justify-between items-center">
            Vendas Recentes
            <span className="text-xs font-normal text-slate-400">Últimos 7 registros</span>
          </h3>
          <div className="h-64 w-full">
            {salesData.length > 0 ? (
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={salesData}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#e2e8f0" />
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} dy={10} />
                  <YAxis axisLine={false} tickLine={false} tick={{fill: '#64748b', fontSize: 12}} prefix="R$ " />
                  <Tooltip 
                    cursor={{fill: '#f1f5f9'}}
                    contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}} 
                  />
                  <Bar dataKey="valor" fill="#10b981" radius={[4, 4, 0, 0]} barSize={40} />
                </BarChart>
              </ResponsiveContainer>
            ) : (
              <div className="h-full flex items-center justify-center text-slate-400 bg-slate-50 rounded-xl border border-dashed border-slate-200">
                Aguardando vendas para gerar o gráfico...
              </div>
            )}
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100 flex flex-col">
          <div className="flex items-center gap-2 mb-6">
            <div className="p-2 bg-yellow-100 text-yellow-600 rounded-lg">
              <Trophy size={20} />
            </div>
            <h3 className="text-lg font-bold text-slate-800">Produtos Mais Vendidos</h3>
          </div>

          <div className="flex-1 overflow-y-auto space-y-4 pr-2">
            {topProducts.length === 0 ? (
              <p className="text-slate-400 text-sm text-center mt-8 italic">Sem dados de vendas.</p>
            ) : (
              topProducts.map((product, index) => (
                <div key={product.id} className="flex items-center gap-3 p-2 hover:bg-slate-50 rounded-xl transition-colors">
                  <span className={`w-6 h-6 flex items-center justify-center text-xs font-bold rounded-full ${
                    index === 0 ? 'bg-yellow-100 text-yellow-700' : 
                    index === 1 ? 'bg-slate-100 text-slate-700' : 
                    index === 2 ? 'bg-amber-100 text-amber-700' : 'bg-slate-50 text-slate-500'
                  }`}>
                    {index + 1}
                  </span>
                  <img src={product.imageUrl} alt="" className="w-10 h-10 rounded-lg object-cover bg-slate-100" />
                  <div className="flex-1 min-w-0">
                    <p className="text-sm font-medium text-slate-800 truncate">{product.name}</p>
                    <p className="text-xs text-slate-500">{product.soldCount} unidades</p>
                  </div>
                  <div className="text-right">
                     <p className="text-xs font-bold text-emerald-600">R$ {product.price.toFixed(2)}</p>
                  </div>
                </div>
              ))
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export interface Product {
  id: string;
  name: string;
  category: string;
  price: number;
  costPrice: number; // Novo campo
  stock: number;
  description: string;
  imageUrl?: string;
}

export interface CartItem extends Product {
  quantity: number;
}

export interface Sale {
  id: string;
  timestamp: number;
  total: number;
  subtotal: number; // Total antes do desconto
  discount: number; // Valor do desconto
  profit: number;   // Lucro da venda (Faturamento - Custo)
  customerName?: string; // Nome do cliente
  items: CartItem[];
  paymentMethod: 'credit' | 'debit' | 'cash' | 'pix';
  status?: 'completed' | 'canceled';
}

export type ViewState = 'dashboard' | 'pos' | 'inventory' | 'history' | 'settings';

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { Product, Sale, CartItem } from '../types';
import { INITIAL_PRODUCTS } from '../constants';

interface Toast {
  id: number;
  message: string;
  type: 'success' | 'error' | 'info';
}

interface StoreContextType {
  products: Product[];
  sales: Sale[];
  cart: CartItem[];
  allTimeStats: { revenue: number; salesCount: number; totalProfit: number };
  isDefaultPassword: boolean;
  toasts: Toast[];
  addToast: (message: string, type?: Toast['type']) => void;
  removeToast: (id: number) => void;
  addProduct: (product: Product) => void;
  updateProduct: (product: Product) => void;
  deleteProduct: (id: string) => void;
  addToCart: (product: Product) => void;
  removeFromCart: (productId: string) => void;
  updateCartQuantity: (productId: string, delta: number) => void;
  clearCart: () => void;
  completeSale: (paymentMethod: Sale['paymentMethod'], discount: number, customerName: string) => void;
  cancelSale: (saleId: string, password: string) => { success: boolean; message: string };
  clearSalesHistory: (password: string) => boolean;
  importData: (data: any, password: string) => boolean;
  resetSystem: (password: string) => boolean;
  updateAdminPassword: (currentPw: string, newPw: string) => boolean;
  exportSalesToCSV: () => void;
}

const StoreContext = createContext<StoreContextType | undefined>(undefined);

export const StoreProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('smartpos_products');
    // Adicionando costPrice retroativo se não existir nos dados salvos
    const loaded = saved ? JSON.parse(saved) : INITIAL_PRODUCTS;
    return loaded.map((p: any) => ({ ...p, costPrice: p.costPrice || p.price * 0.6 }));
  });

  const [sales, setSales] = useState<Sale[]>(() => {
    const saved = localStorage.getItem('smartpos_sales');
    return saved ? JSON.parse(saved) : [];
  });

  const [allTimeStats, setAllTimeStats] = useState(() => {
    const saved = localStorage.getItem('smartpos_alltime_stats');
    return saved ? JSON.parse(saved) : { revenue: 0, salesCount: 0, totalProfit: 0 };
  });

  const [cart, setCart] = useState<CartItem[]>([]);
  const [toasts, setToasts] = useState<Toast[]>([]);
  const [adminPassword, setAdminPassword] = useState<string>(() => localStorage.getItem('smartpos_password') || 'admin');

  const isDefaultPassword = adminPassword === 'admin';

  useEffect(() => localStorage.setItem('smartpos_products', JSON.stringify(products)), [products]);
  useEffect(() => localStorage.setItem('smartpos_sales', JSON.stringify(sales)), [sales]);
  useEffect(() => localStorage.setItem('smartpos_alltime_stats', JSON.stringify(allTimeStats)), [allTimeStats]);
  useEffect(() => localStorage.setItem('smartpos_password', adminPassword), [adminPassword]);

  const addToast = (message: string, type: Toast['type'] = 'info') => {
    const id = Date.now();
    setToasts(prev => [...prev, { id, message, type }]);
    setTimeout(() => removeToast(id), 3000);
  };

  const removeToast = (id: number) => setToasts(prev => prev.filter(t => t.id !== id));

  const addProduct = (product: Product) => {
    setProducts(prev => [...prev, product]);
    addToast('Produto adicionado ao estoque', 'success');
  };

  const updateProduct = (updatedProduct: Product) => {
    setProducts(prev => prev.map(p => p.id === updatedProduct.id ? updatedProduct : p));
    addToast('Produto atualizado', 'success');
  };

  const deleteProduct = (id: string) => {
    setProducts(prev => prev.filter(p => p.id !== id));
    addToast('Produto removido', 'info');
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      const currentProduct = products.find(p => p.id === product.id);
      const availableStock = currentProduct ? currentProduct.stock : 0;

      if (existing) {
        if (existing.quantity < availableStock) {
          return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
        }
        addToast('Limite de estoque atingido', 'error');
        return prev;
      }
      if (availableStock > 0) return [...prev, { ...product, quantity: 1 }];
      return prev;
    });
  };

  const removeFromCart = (productId: string) => setCart(prev => prev.filter(item => item.id !== productId));

  const updateCartQuantity = (productId: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === productId) {
        const currentProduct = products.find(p => p.id === productId);
        const availableStock = currentProduct ? currentProduct.stock : 0;
        const newQty = item.quantity + delta;
        if (newQty > 0 && newQty <= availableStock) return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const clearCart = () => setCart([]);

  const completeSale = (paymentMethod: Sale['paymentMethod'], discount: number, customerName: string) => {
    const subtotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    const total = Math.max(0, subtotal - discount);
    const costTotal = cart.reduce((sum, item) => sum + (item.costPrice * item.quantity), 0);
    const profit = total - costTotal;

    const nextSequentialId = allTimeStats.salesCount + 1;
    const formattedId = nextSequentialId.toString().padStart(4, '0');

    const newSale: Sale = {
      id: formattedId,
      timestamp: Date.now(),
      subtotal,
      total,
      discount,
      profit,
      customerName: customerName.trim() || undefined,
      items: [...cart],
      paymentMethod,
      status: 'completed'
    };

    setSales(prev => [newSale, ...prev]);
    setAllTimeStats(prev => ({
      revenue: prev.revenue + total,
      salesCount: prev.salesCount + 1,
      totalProfit: prev.totalProfit + profit
    }));

    setProducts(prev => prev.map(p => {
      const cartItem = cart.find(c => c.id === p.id);
      if (cartItem) return { ...p, stock: Math.max(0, p.stock - cartItem.quantity) };
      return p;
    }));

    clearCart();
    addToast(`Venda #${formattedId} concluída!`, 'success');
  };

  const cancelSale = (saleId: string, password: string) => {
    if (password !== adminPassword) {
      addToast('Senha administrativa incorreta', 'error');
      return { success: false, message: 'Senha incorreta.' };
    }

    const saleIndex = sales.findIndex(s => s.id === saleId);
    if (saleIndex === -1) return { success: false, message: 'Venda não encontrada.' };

    const saleToCancel = sales[saleIndex];
    if (saleToCancel.status === 'canceled') return { success: false, message: 'Já cancelada.' };

    const updatedSales = [...sales];
    updatedSales[saleIndex] = { ...saleToCancel, status: 'canceled' };
    setSales(updatedSales);

    setAllTimeStats(prev => ({
      revenue: Math.max(0, prev.revenue - saleToCancel.total),
      salesCount: prev.salesCount,
      totalProfit: Math.max(0, prev.totalProfit - saleToCancel.profit)
    }));

    setProducts(prev => prev.map(p => {
      const itemToReturn = saleToCancel.items.find(item => item.id === p.id);
      if (itemToReturn) return { ...p, stock: p.stock + itemToReturn.quantity };
      return p;
    }));

    addToast(`Venda #${saleId} estornada`, 'info');
    return { success: true, message: 'Venda estornada.' };
  };

  const exportSalesToCSV = () => {
    if (sales.length === 0) return addToast('Sem vendas para exportar', 'error');
    const headers = ['ID', 'Data', 'Cliente', 'Subtotal', 'Desconto', 'Total', 'Lucro', 'Metodo', 'Status'];
    const rows = sales.map(s => [
      s.id, new Date(s.timestamp).toLocaleString('pt-BR'), s.customerName || 'N/A',
      s.subtotal.toFixed(2), s.discount.toFixed(2), s.total.toFixed(2), s.profit.toFixed(2),
      s.paymentMethod, s.status
    ]);
    const csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    link.setAttribute("href", URL.createObjectURL(blob));
    link.setAttribute("download", `relatorio_completo_${new Date().toISOString().split('T')[0]}.csv`);
    link.click();
  };

  const updateAdminPassword = (currentPw: string, newPw: string) => {
    if (currentPw === adminPassword) {
      setAdminPassword(newPw);
      addToast('Senha alterada', 'success');
      return true;
    }
    return false;
  };

  const resetSystem = (password: string) => {
    if (password !== adminPassword) return false;
    setProducts(INITIAL_PRODUCTS.map(p => ({ ...p, costPrice: p.price * 0.6 })));
    setSales([]);
    setCart([]);
    setAllTimeStats({ revenue: 0, salesCount: 0, totalProfit: 0 });
    return true;
  };

  const importData = (data: any, password: string) => {
    if (password !== adminPassword) return false;
    if (data.products) setProducts(data.products);
    if (data.sales) setSales(data.sales);
    if (data.allTimeStats) setAllTimeStats(data.allTimeStats);
    return true;
  };

  return (
    <StoreContext.Provider value={{
      products, sales, cart, allTimeStats, isDefaultPassword, toasts,
      addToast, removeToast, addProduct, updateProduct, deleteProduct,
      addToCart, removeFromCart, updateCartQuantity, clearCart,
      completeSale, cancelSale, clearSalesHistory: (pw) => { if (pw === adminPassword) { setSales([]); return true; } return false; },
      importData, resetSystem, updateAdminPassword, exportSalesToCSV
    }}>
      {children}
    </StoreContext.Provider>
  );
};

export const useStore = () => {
  const context = useContext(StoreContext);
  if (!context) throw new Error('useStore must be used within a StoreProvider');
  return context;
};

