import { GoogleGenAI } from "@google/genai";
import { Product, Sale } from '../types';

// Fix: Strictly use process.env.API_KEY directly in the constructor as per guidelines
const getAiClient = () => {
  return new GoogleGenAI({ apiKey: process.env.API_KEY! });
};

export const generateProductDescription = async (productName: string, category: string): Promise<string> => {
  try {
    const ai = getAiClient();
    const prompt = `Escreva uma descrição atraente e curta (máximo 2 frases) para um produto de venda chamado "${productName}" que pertence à categoria "${category}". O tom deve ser vendedor e apetitoso/útil.`;

    // Fix: Using correct model for basic text tasks
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });

    // Fix: Accessing .text property directly (not as a method)
    return response.text || "Descrição não disponível.";
  } catch (error) {
    console.error("Erro ao gerar descrição:", error);
    return "Não foi possível gerar a descrição automaticamente.";
  }
};

export const getBusinessInsights = async (products: Product[], sales: Sale[], query: string): Promise<string> => {
  try {
    const ai = getAiClient();

    // Create a minimized context string to save tokens but provide info
    const stockContext = products.map(p => `${p.name} (Estoque: ${p.stock})`).join(', ');
    const salesContext = `Total de vendas registradas: ${sales.length}. Faturamento total: R$ ${sales.reduce((acc, s) => acc + s.total, 0).toFixed(2)}.`;

    const systemInstruction = `Você é um assistente de negócios inteligente para um sistema de PDV. 
    Analise os dados fornecidos e responda à pergunta do usuário.
    Dados de Estoque: ${stockContext}
    Dados de Vendas: ${salesContext}
    Seja conciso, profissional e útil.`;

    // Fix: Using gemini-3-pro-preview for complex reasoning and data analysis tasks
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: query,
      config: {
        systemInstruction: systemInstruction,
      }
    });

    // Fix: Accessing .text property directly (not as a method)
    return response.text || "Sem insights disponíveis no momento.";
  } catch (error) {
    console.error("Erro ao buscar insights:", error);
    return "Desculpe, estou com dificuldades para analisar seus dados agora.";
  }
};

import React, { useRef, useState } from 'react';
import { useStore } from '../context/StoreContext';
import { Download, Upload, Trash2, AlertTriangle, Save, RefreshCw, X, Lock, Shield, Key } from 'lucide-react';

export const Settings: React.FC = () => {
  const { products, sales, importData, resetSystem, updateAdminPassword, isDefaultPassword } = useStore();
  const fileInputRef = useRef<HTMLInputElement>(null);

  const [modalType, setModalType] = useState<'restore' | 'reset' | 'reset-initial' | null>(null);
  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [pendingFileContent, setPendingFileContent] = useState<any>(null);
  const [error, setError] = useState('');

  const [pwdForm, setPwdForm] = useState({ current: '', new: '', confirm: '' });
  const [pwdMessage, setPwdMessage] = useState<{type: 'success' | 'error', text: string} | null>(null);

  const handleExportBackup = () => {
    const data = { timestamp: Date.now(), version: 1, products, sales };
    const blob = new Blob([JSON.stringify(data, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `smartpos-backup-${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const content = event.target?.result as string;
        const parsed = JSON.parse(content);
        if (!parsed.products || !parsed.sales) throw new Error("Inválido");
        setPendingFileContent(parsed);
        setModalType('restore');
        if (fileInputRef.current) fileInputRef.current.value = '';
      } catch (err) { alert("Erro no backup."); }
    };
    reader.readAsText(file);
  };

  const handleSubmitPassword = (e: React.FormEvent) => {
    e.preventDefault();
    setError('');
    if (modalType === 'restore') {
      if (importData(pendingFileContent, password)) closeModal();
      else setError('Senha incorreta.');
    } else if (modalType === 'reset') {
      if (resetSystem(password)) closeModal();
      else setError('Senha incorreta.');
    } else if (modalType === 'reset-initial') {
      if (password.length < 4) { setError('Mínimo 4 caracteres.'); return; }
      if (password !== confirmPassword) { setError('Senhas não conferem.'); return; }
      if (resetSystem('admin') && updateAdminPassword('admin', password)) closeModal();
      else setError('Erro crítico.');
    }
  };

  const handleChangePassword = (e: React.FormEvent) => {
    e.preventDefault();
    setPwdMessage(null);
    if (pwdForm.new.length < 4) { setPwdMessage({ type: 'error', text: 'Mínimo 4 caracteres.' }); return; }
    if (pwdForm.new !== pwdForm.confirm) { setPwdMessage({ type: 'error', text: 'Confirmação não confere.' }); return; }
    if (updateAdminPassword(pwdForm.current, pwdForm.new)) {
      setPwdMessage({ type: 'success', text: 'Senha alterada!' });
      setPwdForm({ current: '', new: '', confirm: '' });
    } else setPwdMessage({ type: 'error', text: 'Senha atual incorreta.' });
  };

  const closeModal = () => {
    setModalType(null);
    setPassword('');
    setConfirmPassword('');
    setError('');
    setPendingFileContent(null);
  };

  const isDanger = modalType === 'reset' || modalType === 'reset-initial';

  return (
    <div className="space-y-8 animate-fade-in max-w-4xl pb-12">
      <header>
        <h2 className="text-3xl font-black text-slate-900">Configurações do Sistema</h2>
        <p className="text-slate-500 mt-1">Gerencie segurança, integridade de dados e backups.</p>
      </header>

      <div className="grid gap-8">
        <div className="bg-white p-8 rounded-3xl shadow-sm border-2 border-slate-100">
           <div className="flex items-start gap-4 mb-8">
            <div className="p-4 bg-indigo-50 text-indigo-600 rounded-2xl border border-indigo-100">
              <Shield size={28} />
            </div>
            <div>
              <h3 className="text-xl font-black text-slate-800">Segurança de Acesso</h3>
              <p className="text-sm text-slate-500">Proteja ações críticas alterando sua senha de administrador.</p>
            </div>
          </div>

          <form onSubmit={handleChangePassword} className="max-w-xl bg-slate-50 p-8 rounded-3xl border-2 border-slate-200 space-y-6">
             {pwdMessage && (
              <div className={`p-4 rounded-xl text-sm font-bold animate-fade-in flex items-center gap-3 ${pwdMessage.type === 'success' ? 'bg-emerald-100 text-emerald-700 border border-emerald-200' : 'bg-red-100 text-red-700 border border-red-200'}`}>
                {pwdMessage.type === 'success' ? <RefreshCw size={16} /> : <AlertTriangle size={16} />}
                {pwdMessage.text}
              </div>
            )}

            <div className="space-y-2">
              <label className="text-xs font-black text-slate-500 uppercase tracking-widest flex items-center gap-2">
                <Key size={14} className="text-indigo-500" /> Senha Atual do Administrador
              </label>
              <input 
                type="password" 
                placeholder="••••••••"
                value={pwdForm.current}
                onChange={e => setPwdForm({...pwdForm, current: e.target.value})}
                className="w-full px-5 py-4 bg-white border-2 border-slate-300 rounded-2xl text-lg font-black focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 focus:outline-none transition-all placeholder:text-slate-200"
                required
              />
            </div>

            <div className="grid grid-cols-1 sm:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-xs font-black text-slate-500 uppercase tracking-widest">Nova Senha</label>
                <input 
                  type="password" 
                  placeholder="Mín. 4 dígitos"
                  value={pwdForm.new}
                  onChange={e => setPwdForm({...pwdForm, new: e.target.value})}
                  className="w-full px-5 py-4 bg-white border-2 border-slate-300 rounded-2xl text-lg font-black focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 focus:outline-none transition-all placeholder:text-slate-200"
                  required
                />
              </div>
              <div className="space-y-2">
                <label className="text-xs font-black text-slate-500 uppercase tracking-widest">Confirmar Nova</label>
                <input 
                  type="password" 
                  placeholder="Repita a nova"
                  value={pwdForm.confirm}
                  onChange={e => setPwdForm({...pwdForm, confirm: e.target.value})}
                  className="w-full px-5 py-4 bg-white border-2 border-slate-300 rounded-2xl text-lg font-black focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 focus:outline-none transition-all placeholder:text-slate-200"
                  required
                />
              </div>
            </div>

            <button type="submit" className="w-full px-6 py-4 bg-indigo-600 text-white rounded-2xl font-black uppercase tracking-widest text-xs hover:bg-indigo-700 transition-all shadow-xl shadow-indigo-600/20 active:scale-[0.98]">
              Confirmar Alteração de Senha
            </button>
          </form>
        </div>

        <div className="bg-white p-8 rounded-3xl shadow-sm border-2 border-slate-100">
          <div className="flex items-start gap-4 mb-8">
            <div className="p-4 bg-blue-50 text-blue-600 rounded-2xl border border-blue-100">
              <Save size={28} />
            </div>
            <div>
              <h3 className="text-xl font-black text-slate-800">Manutenção de Dados</h3>
              <p className="text-sm text-slate-500">Exporte ou restaure suas informações em arquivos locais.</p>
            </div>
          </div>

          <div className="flex flex-col md:flex-row gap-6">
            <button onClick={handleExportBackup} className="flex-1 flex items-center justify-center gap-4 bg-slate-900 text-white px-8 py-6 rounded-3xl hover:bg-slate-800 transition-all shadow-xl active:scale-[0.98]">
              <Download size={24} className="text-blue-400" />
              <div className="text-left">
                <span className="block font-black uppercase tracking-widest text-xs">Fazer Backup</span>
                <span className="text-[10px] text-slate-500 font-bold">Gerar arquivo .JSON</span>
              </div>
            </button>

            <button onClick={() => fileInputRef.current?.click()} className="flex-1 flex items-center justify-center gap-4 bg-white border-2 border-slate-300 text-slate-700 px-8 py-6 rounded-3xl hover:border-emerald-500 hover:text-emerald-600 transition-all shadow-sm active:scale-[0.98] group">
              <Upload size={24} className="group-hover:text-emerald-500" />
              <div className="text-left">
                <span className="block font-black uppercase tracking-widest text-xs">Importar Dados</span>
                <span className="text-[10px] text-slate-400 font-bold">Substituir dados atuais</span>
              </div>
            </button>
            <input type="file" ref={fileInputRef} onChange={handleFileChange} accept=".json" className="hidden" />
          </div>
        </div>

        <div className="bg-red-50 p-8 rounded-3xl border-2 border-red-100 relative overflow-hidden group">
          <div className="absolute -top-6 -right-6 opacity-5 rotate-12 group-hover:scale-110 transition-transform duration-500">
            <AlertTriangle size={180} className="text-red-600" />
          </div>
          <div className="flex items-start gap-4 mb-6 relative z-10">
            <div className="p-4 bg-white text-red-600 rounded-2xl shadow-sm">
              <Trash2 size={28} />
            </div>
            <div>
              <h3 className="text-xl font-black text-red-900">Área Crítica</h3>
              <p className="text-sm text-red-700">Ações irreversiveis que limpam todo o histórico de operações.</p>
            </div>
          </div>
          <button onClick={() => setModalType(isDefaultPassword ? 'reset-initial' : 'reset')} className="relative z-10 w-full md:w-auto px-10 py-4 bg-red-600 text-white rounded-2xl font-black uppercase tracking-widest text-xs hover:bg-red-700 transition-all shadow-xl shadow-red-600/20 active:scale-[0.98] flex items-center justify-center gap-3">
            <RefreshCw size={18} /> Reset de Fábrica
          </button>
        </div>
      </div>

      {modalType && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center p-4 bg-black/70 backdrop-blur-md animate-fade-in">
          <div className="bg-white rounded-[2rem] shadow-2xl w-full max-w-md overflow-hidden border border-slate-200">
            <div className={`p-6 border-b border-slate-100 flex justify-between items-center ${isDanger ? 'bg-red-50 text-red-800' : 'bg-blue-50 text-blue-800'}`}>
              <h3 className="text-lg font-black flex items-center gap-2 uppercase tracking-tight">
                {isDanger ? <AlertTriangle size={20} /> : <Lock size={20} />}
                {modalType === 'restore' ? 'Validar Restauração' : modalType === 'reset-initial' ? 'Primeiro Uso' : 'Confirmar Limpeza'}
              </h3>
              <button onClick={closeModal} className="p-2 hover:bg-white/50 rounded-full transition-colors"><X size={24}/></button>
            </div>

            <form onSubmit={handleSubmitPassword} className="p-8 space-y-6">
              <div className="p-4 bg-slate-50 rounded-2xl text-sm text-slate-600 border border-slate-100 font-medium leading-relaxed">
                {modalType === 'reset' && "Esta ação apagará permanentemente todos os produtos e vendas. Confirme com sua senha administrativa."}
                {modalType === 'restore' && "Todos os dados atuais serão removidos e substituídos pelos do arquivo. Confirme com sua senha."}
                {modalType === 'reset-initial' && "Crie sua senha de administrador antes de realizar o primeiro reset total do sistema."}
              </div>

              <div className="space-y-4">
                <div className="space-y-2">
                  <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">{modalType === 'reset-initial' ? 'Nova Senha Admin' : 'Senha do Sistema'}</label>
                  <input 
                    autoFocus
                    type="password" 
                    value={password}
                    onChange={e => setPassword(e.target.value)}
                    className="w-full px-5 py-4 bg-white border-2 border-slate-300 rounded-2xl text-xl font-black focus:border-emerald-500 focus:ring-4 focus:ring-emerald-500/10 focus:outline-none transition-all placeholder:text-slate-200"
                    placeholder="••••••••"
                    required
                  />
                </div>
                {modalType === 'reset-initial' && (
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-slate-400 uppercase tracking-[0.2em]">Repita a Senha</label>
                    <input 
                      type="password" 
                      value={confirmPassword}
                      onChange={e => setConfirmPassword(e.target.value)}
                      className="w-full px-5 py-4 bg-white border-2 border-slate-300 rounded-2xl text-xl font-black focus:border-emerald-500 focus:ring-4 focus:ring-emerald-500/10 focus:outline-none transition-all placeholder:text-slate-200"
                      placeholder="••••••••"
                      required
                    />
                  </div>
                )}
              </div>

              {error && <div className="p-3 bg-red-50 text-red-600 rounded-xl text-xs font-bold border border-red-100 flex items-center gap-2 animate-shake"><AlertTriangle size={14} />{error}</div>}

              <div className="flex gap-4 pt-2">
                <button type="button" onClick={closeModal} className="flex-1 px-4 py-4 border-2 border-slate-200 text-slate-500 rounded-2xl hover:bg-slate-50 font-black text-xs uppercase tracking-widest transition-colors">Cancelar</button>
                <button type="submit" className={`flex-1 px-4 py-4 text-white rounded-2xl font-black text-xs uppercase tracking-widest shadow-lg transition-all active:scale-[0.98] ${isDanger ? 'bg-red-600 hover:bg-red-700 shadow-red-200' : 'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-200'}`}>Confirmar</button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo } from 'react';
import { useStore } from '../context/StoreContext';
import { Clock, CreditCard, Banknote, QrCode, AlertTriangle, X, RotateCcw, Ban, ShieldCheck, Key, Info, Calendar, Filter, ChevronRight, FileDown, User } from 'lucide-react';

export const SalesHistory: React.FC = () => {
  const { sales, cancelSale, isDefaultPassword, updateAdminPassword, exportSalesToCSV } = useStore();
  const [saleToCancel, setSaleToCancel] = useState<string | null>(null);
  const [filterMode, setFilterMode] = useState<'24h' | 'custom'>('24h');
  const [startDate, setStartDate] = useState<string>(() => {
    const yesterday = new Date();
    yesterday.setDate(yesterday.getDate() - 1);
    return yesterday.toISOString().split('T')[0];
  });

  const [password, setPassword] = useState('');
  const [confirmPassword, setConfirmPassword] = useState('');
  const [error, setError] = useState('');

  const filteredSales = useMemo(() => {
    const now = Date.now();
    const twentyFourHoursAgo = now - (24 * 60 * 60 * 1000);
    return sales.filter(sale => {
      if (filterMode === '24h') return sale.timestamp >= twentyFourHoursAgo;
      const selectedStart = new Date(startDate + 'T00:00:00').getTime();
      return sale.timestamp >= selectedStart;
    });
  }, [sales, filterMode, startDate]);

  const getPaymentIcon = (method: string) => {
    switch (method) {
      case 'credit': return <CreditCard size={16} className="text-blue-500" />;
      case 'debit': return <CreditCard size={16} className="text-sky-500" />;
      case 'cash': return <Banknote size={16} className="text-emerald-500" />;
      case 'pix': return <QrCode size={16} className="text-teal-500" />;
      default: return <CreditCard size={16} />;
    }
  };

  const handleCancelSale = (e: React.FormEvent) => {
    e.preventDefault();
    if (!saleToCancel) return;
    setError('');
    if (isDefaultPassword) {
      if (password.length < 4) { setError('Mínimo 4 caracteres.'); return; }
      if (password !== confirmPassword) { setError('Senhas não conferem.'); return; }
      if (cancelSale(saleToCancel, 'admin').success) {
        updateAdminPassword('admin', password);
        closeModals();
      } else setError('Erro ao estornar.');
    } else {
      if (cancelSale(saleToCancel, password).success) closeModals();
      else setError('Senha incorreta.');
    }
  };

  const closeModals = () => {
    setSaleToCancel(null);
    setPassword('');
    setConfirmPassword('');
    setError('');
  };

  return (
    <div className="space-y-6 animate-fade-in">
      <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 bg-white p-6 rounded-2xl border border-slate-200 shadow-sm">
        <div>
          <h2 className="text-2xl font-bold text-slate-800">Histórico de Movimentação</h2>
          <p className="text-slate-500">Consulte vendas, estorne pagamentos e gere relatórios.</p>
        </div>
        <button onClick={exportSalesToCSV} className="flex items-center gap-3 px-6 py-3 bg-slate-800 text-white rounded-xl hover:bg-slate-700 transition-all shadow-md font-black text-xs uppercase tracking-widest active:scale-95">
          <FileDown size={18} className="text-emerald-400" /> Relatório CSV
        </button>
      </header>

      <div className="bg-white p-5 rounded-2xl border-2 border-slate-200 shadow-sm flex flex-col md:flex-row items-center gap-6">
        <div className="flex items-center gap-3 text-slate-500 font-black text-xs uppercase tracking-widest">
          <Filter size={18} className="text-indigo-500" /> Filtros de Busca
        </div>

        <div className="flex p-1.5 bg-slate-100 rounded-2xl w-full md:w-auto border border-slate-200">
          <button onClick={() => setFilterMode('24h')} className={`px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${filterMode === '24h' ? 'bg-white text-emerald-600 shadow-md' : 'text-slate-500 hover:text-slate-800'}`}>Últimas 24h</button>
          <button onClick={() => setFilterMode('custom')} className={`px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all ${filterMode === 'custom' ? 'bg-white text-emerald-600 shadow-md' : 'text-slate-500 hover:text-slate-800'}`}>Personalizado</button>
        </div>

        {filterMode === 'custom' && (
          <div className="flex items-center gap-4 w-full md:w-auto animate-fade-in">
            <ChevronRight size={20} className="text-slate-300 hidden md:block" />
            <div className="relative flex-1 md:flex-none group">
              <Calendar className="absolute left-4 top-1/2 -translate-y-1/2 text-emerald-500 group-focus-within:scale-110 transition-transform" size={18} />
              <input 
                type="date" 
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
                className="pl-12 pr-6 py-3 bg-white border-2 border-slate-300 rounded-xl text-sm font-black text-slate-700 focus:border-emerald-500 focus:ring-4 focus:ring-emerald-500/10 focus:outline-none transition-all cursor-pointer shadow-sm"
              />
            </div>
          </div>
        )}
      </div>

      <div className="space-y-4">
        {filteredSales.map(sale => {
          const isCanceled = sale.status === 'canceled';
          return (
