export type ViewState = 'dashboard' | 'pos' | 'inventory' | 'history' | 'settings';

import React, { createContext, useContext, useState, useEffect, ReactNode } from 'react';
import { Product, Sale, CartItem } from '../types';
import { INITIAL_PRODUCTS } from '../constants';

interface Toast {
  id: number;
  message: string;
  type: 'success' | 'error' | 'info';
}

interface StoreContextType {
  products: Product[];
  sales: Sale[];
  cart: CartItem[];
  allTimeStats: { revenue: number; salesCount: number; totalProfit: number };
  isDefaultPassword: boolean;
  toasts: Toast[];
  addToast: (message: string, type?: Toast['type']) => void;
  removeToast: (id: number) => void;
  addProduct: (product: Product) => void;
  updateProduct: (product: Product) => void;
  deleteProduct: (id: string) => void;
  addToCart: (product: Product) => void;
  removeFromCart: (productId: string) => void;
  updateCartQuantity: (productId: string, delta: number) => void;
  clearCart: () => void;
  completeSale: (paymentMethod: Sale['paymentMethod'], discount: number, customerName: string, surcharge: number) => void;
  cancelSale: (saleId: string, password: string) => { success: boolean; message: string };
  clearSalesHistory: (password: string) => boolean;
  importData: (data: any, password: string) => boolean;
  resetSystem: (password: string) => boolean;
  updateAdminPassword: (currentPw: string, newPw: string) => boolean;
  exportSalesToCSV: () => void;
}

const StoreContext = createContext<StoreContextType | undefined>(undefined);

export const StoreProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [products, setProducts] = useState<Product[]>(() => {
    const saved = localStorage.getItem('smartpos_products');
    const loaded = saved !== null ? JSON.parse(saved) : INITIAL_PRODUCTS;
    return loaded.map((p: any) => ({ ...p, costPrice: p.costPrice || p.price * 0.6 }));
  });

  const [sales, setSales] = useState<Sale[]>(() => {
    const saved = localStorage.getItem('smartpos_sales');
    return saved ? JSON.parse(saved) : [];
  });

  const [allTimeStats, setAllTimeStats] = useState(() => {
    const saved = localStorage.getItem('smartpos_alltime_stats');
    return saved ? JSON.parse(saved) : { revenue: 0, salesCount: 0, totalProfit: 0 };
  });

  const [cart, setCart] = useState<CartItem[]>([]);
  const [toasts, setToasts] = useState<Toast[]>([]);
  const [adminPassword, setAdminPassword] = useState<string>(() => localStorage.getItem('smartpos_password') || 'admin');

  const isDefaultPassword = adminPassword === 'admin';

  useEffect(() => localStorage.setItem('smartpos_products', JSON.stringify(products)), [products]);
  useEffect(() => localStorage.setItem('smartpos_sales', JSON.stringify(sales)), [sales]);
  useEffect(() => localStorage.setItem('smartpos_alltime_stats', JSON.stringify(allTimeStats)), [allTimeStats]);
  useEffect(() => localStorage.setItem('smartpos_password', adminPassword), [adminPassword]);

  const addToast = (message: string, type: Toast['type'] = 'info') => {
    const id = Date.now();
    setToasts(prev => [...prev, { id, message, type }]);
    setTimeout(() => removeToast(id), 3000);
  };

  const removeToast = (id: number) => setToasts(prev => prev.filter(t => t.id !== id));

  const addProduct = (product: Product) => {
    setProducts(prev => [...prev, product]);
    addToast('Produto adicionado ao estoque', 'success');
  };

  const updateProduct = (updatedProduct: Product) => {
    setProducts(prev => prev.map(p => p.id === updatedProduct.id ? updatedProduct : p));
    addToast('Produto atualizado', 'success');
  };

  const deleteProduct = (id: string) => {
    setProducts(prev => prev.filter(p => p.id !== id));
    setCart(prev => prev.filter(item => item.id !== id));
    addToast('Produto removido do sistema', 'info');
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      const currentProduct = products.find(p => p.id === product.id);
      const availableStock = currentProduct ? currentProduct.stock : 0;

      if (existing) {
        if (existing.quantity < availableStock) {
          return prev.map(item => item.id === product.id ? { ...item, quantity: item.quantity + 1 } : item);
        }
        addToast('Limite de estoque atingido', 'error');
        return prev;
      }
      if (availableStock > 0) return [...prev, { ...product, quantity: 1 }];
      return prev;
    });
  };

  const removeFromCart = (productId: string) => setCart(prev => prev.filter(item => item.id !== productId));

  const updateCartQuantity = (productId: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.id === productId) {
        const currentProduct = products.find(p => p.id === productId);
        const availableStock = currentProduct ? currentProduct.stock : 0;
        const newQty = item.quantity + delta;
        if (newQty > 0 && newQty <= availableStock) return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const clearCart = () => setCart([]);

  const completeSale = (paymentMethod: Sale['paymentMethod'], discount: number, customerName: string, surcharge: number) => {
    const subtotal = cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    // O total final é subtotal - desconto + taxa
    const total = Math.max(0, subtotal - discount + surcharge);
    const costTotal = cart.reduce((sum, item) => sum + (item.costPrice * item.quantity), 0);
    const profit = total - costTotal;

    const nextSequentialId = allTimeStats.salesCount + 1;
    const formattedId = nextSequentialId.toString().padStart(4, '0');

    const newSale: Sale = {
      id: formattedId,
      timestamp: Date.now(),
      subtotal,
      total,
      discount,
      surcharge,
      profit,
      customerName: customerName.trim() || undefined,
      items: [...cart],
      paymentMethod,
      status: 'completed'
    };

    setSales(prev => [newSale, ...prev]);
    setAllTimeStats(prev => ({
      revenue: prev.revenue + total,
      salesCount: prev.salesCount + 1,
      totalProfit: prev.totalProfit + profit
    }));

    setProducts(prev => prev.map(p => {
      const cartItem = cart.find(c => c.id === p.id);
      if (cartItem) return { ...p, stock: Math.max(0, p.stock - cartItem.quantity) };
      return p;
    }));

    clearCart();
    addToast(`Venda #${formattedId} concluída!`, 'success');
  };

  const cancelSale = (saleId: string, password: string) => {
    if (password !== adminPassword) {
      addToast('Senha administrativa incorreta', 'error');
      return { success: false, message: 'Senha incorreta.' };
    }

    const saleIndex = sales.findIndex(s => s.id === saleId);
    if (saleIndex === -1) return { success: false, message: 'Venda não encontrada.' };

    const saleToCancel = sales[saleIndex];
    if (saleToCancel.status === 'canceled') return { success: false, message: 'Já cancelada.' };

    const updatedSales = [...sales];
    updatedSales[saleIndex] = { ...saleToCancel, status: 'canceled' };
    setSales(updatedSales);

    setAllTimeStats(prev => ({
      revenue: Math.max(0, prev.revenue - saleToCancel.total),
      salesCount: prev.salesCount,
      totalProfit: Math.max(0, prev.totalProfit - saleToCancel.profit)
    }));

    setProducts(prev => prev.map(p => {
      const itemToReturn = saleToCancel.items.find(item => item.id === p.id);
      if (itemToReturn) return { ...p, stock: p.stock + itemToReturn.quantity };
      return p;
    }));

    addToast(`Venda #${saleId} estornada`, 'info');
    return { success: true, message: 'Venda estornada.' };
  };

  const exportSalesToCSV = () => {
    if (sales.length === 0) return addToast('Sem vendas para exportar', 'error');
    const headers = ['ID', 'Data', 'Cliente', 'Subtotal', 'Desconto', 'Taxa/Acrescimo', 'Total', 'Lucro', 'Metodo', 'Status'];
    const rows = sales.map(s => [
      s.id, new Date(s.timestamp).toLocaleString('pt-BR'), s.customerName || 'N/A',
      s.subtotal.toFixed(2), s.discount.toFixed(2), s.surcharge.toFixed(2), s.total.toFixed(2), s.profit.toFixed(2),
      s.paymentMethod, s.status
    ]);
    const csvContent = [headers, ...rows].map(e => e.join(",")).join("\n");
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement("a");
    link.setAttribute("href", URL.createObjectURL(blob));
    link.setAttribute("download", `relatorio_completo_${new Date().toISOString().split('T')[0]}.csv`);
    link.click();
  };

  const updateAdminPassword = (currentPw: string, newPw: string) => {
    if (currentPw === adminPassword) {
      setAdminPassword(newPw);
      addToast('Senha alterada', 'success');
      return true;
    }
    return false;
  };

  const resetSystem = (password: string) => {
    if (password !== adminPassword) return false;
    setProducts([]);
    setSales([]);
    setCart([]);
    setAllTimeStats({ revenue: 0, salesCount: 0, totalProfit: 0 });
    addToast('Sistema limpo com sucesso!', 'success');
    return true;
  };

  const importData = (data: any, password: string) => {
    if (password !== adminPassword) return false;
    if (data.products) setProducts(data.products);
    if (data.sales) setSales(data.sales);
    if (data.allTimeStats) setAllTimeStats(data.allTimeStats);
    addToast('Dados importados com sucesso!', 'success');
    return true;
  };

  return (
    <StoreContext.Provider value={{
      products, sales, cart, allTimeStats, isDefaultPassword, toasts,
      addToast, removeToast, addProduct, updateProduct, deleteProduct,
      addToCart, removeFromCart, updateCartQuantity, clearCart,
      completeSale, cancelSale, clearSalesHistory: (pw) => { if (pw === adminPassword) { setSales([]); return true; } return false; },
      importData, resetSystem, updateAdminPassword, exportSalesToCSV
    }}>
      {children}
    </StoreContext.Provider>
  );
};

export const useStore = () => {
  const context = useContext(StoreContext);
  if (!context) throw new Error('useStore must be used within a StoreProvider');
  return context;
};

